INSERT INTO `ds_activity` VALUES (1,8,'端午节包粽子大赛','端午节来临，社区组织包粽子大赛！\n时间：6月8日上午9:00-12:00\n比赛规则：每户派1名代表，限时30分钟，比谁包得又快又好。\n奖品：一等奖1名（购物卡200元），二等奖3名（购物卡100元），参与奖（粽子礼盒一份）。','','2026-06-08 09:00:00','2026-06-08 12:00:00','阳光花园中心广场',50,15,2,'2026-06-01 09:00:00','2026-06-03 01:34:20',NULL),(2,8,'六一儿童节亲子运动会','欢乐六一，亲子同乐！\n活动项目：三人四足、袋鼠跳、趣味接球、画布涂鸦\n适合年龄：3-12岁儿童\n每位小朋友都有精美礼品哦！','','2026-06-01 14:00:00','2026-06-01 17:00:00','阳光花园篮球场',30,13,4,'2026-05-25 14:00:00','2026-06-03 01:34:20',NULL),(3,8,'小区消防演习','消防安全人人有责！\n内容：1.消防知识讲座\n2.灭火器使用实操\n3.逃生演练\n请各户至少1人参加。','','2026-06-15 10:00:00','2026-06-15 11:30:00','阳光花园消防通道',0,0,2,'2026-06-08 10:00:00','2026-06-04 19:13:42',NULL),(4,9,'夏日纳凉电影节','连续三天，每晚7:30在小区广场放映经典电影！\n6月20日：《我和我的祖国》\n6月21日：《哪吒之魔童降世》\n6月22日：《流浪地球》\n现场提供免费爆米花和绿豆汤。','','2026-06-20 09:00:00','2026-06-22 21:30:00','翠苑新城中心广场',100,15,2,'2026-06-13 09:00:00','2026-06-03 01:34:20',NULL),(5,9,'社区义诊活动','联合市第二人民医院举办免费义诊活动！\n服务项目：血压测量、血糖检测、中医问诊、眼科检查\n欢迎各位业主踊跃参加，特别是老年朋友。','','2026-03-15 08:30:00','2026-03-15 12:00:00','翠苑新城3号楼活动室',80,9,4,'2026-03-08 08:30:00','2026-06-03 01:34:20',NULL),(6,9,'春季植树活动','美化家园，从我做起！\n社区规划在小区北侧绿化带种植樱花树，需要志愿者帮忙。\n树苗和工具由物业提供，请大家积极参与。','','2026-04-12 09:00:00','2026-04-12 11:00:00','翠苑新城北侧绿化带',20,0,5,'2026-04-05 09:00:00','2026-06-02 17:34:20',NULL),(7,12,'植树','植树','','2026-06-04 00:00:00','2026-06-06 00:00:00','临平公园',10,3,3,'2026-06-04 19:10:08','2026-06-05 15:52:51',NULL),(8,12,'社区AI学习','社区AI学习','','2026-06-04 00:00:00','2026-06-05 00:00:00','小区会议室',2,2,3,'2026-06-04 23:39:24','2026-06-05 08:25:45',NULL),(9,12,'专家义诊','专家义诊\n','','2026-06-09 18:47:00','2026-06-10 18:47:00','小区公共区域',99,1,3,'2026-06-09 18:48:02','2026-06-09 18:48:39',NULL);
