INSERT INTO `ds_ai_chat_log` VALUES (1,15,'我家水管漏水怎么办？','您好！请先关闭水阀，通过公众号提交报修工单。','chat','维修','2026-06-08 21:29:33'),(2,15,'电梯坏了怎么报修？','电梯故障属紧急事项！请立即拨打物业电话。','chat','维修','2026-06-08 20:29:33'),(3,15,'楼道灯不亮了','已记录，电工将尽快修复。','chat','维修','2026-06-08 19:29:33'),(4,15,'小区停水了','因市政管网检修，预计今日18:00恢复供水。','chat','咨询','2026-06-08 18:29:33'),(5,15,'物业费怎么交？','住宅2.8元/㎡/月。可通过公众号在线缴费。','chat','咨询','2026-06-08 16:29:33'),(6,15,'楼道有异味','已记录清洁工单，保洁人员将前往处理。','chat','卫生','2026-06-08 13:29:33'),(7,15,'装修需要什么手续？','1)填装修申请表 2)提交方案 3)缴押金 4)办出入证。','chat','咨询','2026-06-08 09:29:33'),(8,15,'暖气不热','可能原因：管道有气需排气、滤网堵塞需清洗。','chat','维修','2026-06-07 21:29:33'),(9,0,'','您好！请描述您遇到的问题，我会帮您快速报修。比如：\"我家厨房水龙头漏水了\"','greet','','2026-06-08 22:26:53'),(10,0,'厨房水龙头漏水了','✅ 已识别您的报修需求：\n📋 类型：水电维修 → 归类为【水电维修】\n📍 厨房\n\n确认提交报修单吗？回复「确认」即可提交，或补充更多信息。','confirm','水电','2026-06-08 22:27:26'),(11,0,'门锁坏','✅ 已识别您的报修需求：\n📋 类型：门窗维修 → 归类为【门窗维修】\n📍 待确认\n\n确认提交报修单吗？回复「确认」即可提交，或补充更多信息。','confirm','门窗','2026-06-08 22:28:15'),(12,0,'门锁坏','🎉 报修单已生成！\n📋 工单号：DSR202606082228161624\n📝 标题：门锁坏\n🔧 类型：门窗维修\n👷 已自动派单给维修师傅，请保持电话畅通！\n\n💡 您可以凭工单号随时查询处理进度。','submit','门窗','2026-06-08 22:28:16'),(13,0,'厨房水龙头漏水严重','🎉 报修单已生成！\n📋 工单号：DSR202606082250085755\n📝 标题：厨房水龙头漏水严重\n🔧 类型：水电维修\n⚠️ 紧急标记已生效\n👷 已自动派单给维修师傅，请保持电话畅通！\n\n💡 您可以凭工单号随时查询处理进度。','submit','水电','2026-06-08 22:50:08'),(14,0,'车位被占','✅ 已识别您的报修需求：\n📋 类型：停车维修 → 归类为【停车维修】\n📍 待确认\n\n确认提交报修单吗？回复「确认」即可提交，或补充更多信息。','confirm','停车','2026-06-08 23:37:05'),(15,0,'车位被占','🎉 报修单已生成！\n📋 工单号：DSR202606082337078794\n📝 标题：车位被占\n🔧 类型：停车维修\n👷 已自动派单给维修师傅，请保持电话畅通！\n\n💡 您可以凭工单号随时查询处理进度。','submit','停车','2026-06-08 23:37:07'),(16,0,'漏水','✅ 已识别您的报修需求：\n📋 类型：水电维修 → 归类为【水电维修】\n📍 待确认\n\n确认提交报修单吗？回复「确认」即可提交，或补充更多信息。','confirm','水电','2026-06-08 23:50:12'),(17,0,'不制冷','✅ 已识别您的报修需求：\n📋 类型：空调维修 → 归类为【空调维修】\n📍 待确认\n\n确认提交报修单吗？回复「确认」即可提交，或补充更多信息。','confirm','空调','2026-06-09 00:06:57'),(18,0,'不制冷','🎉 报修单已生成！\n📋 工单号：DSR202606090007109717\n📝 标题：不制冷\n🔧 类型：空调维修\n👷 已自动派单给维修师傅，请保持电话畅通！\n\n💡 您可以凭工单号随时查询处理进度。','submit','空调','2026-06-09 00:07