--
-- Table structure for table `ds_bill`
--

DROP TABLE IF EXISTS `ds_bill`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_bill` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `bill_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '账单编号',
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `owner_id` int unsigned NOT NULL DEFAULT '0' COMMENT '业主ID',
  `room_id` int unsigned NOT NULL DEFAULT '0' COMMENT '房间ID',
  `charge_item_id` int unsigned NOT NULL DEFAULT '0' COMMENT '收费项目ID',
  `charge_item_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '收费项目名称',
  `bill_period` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '账期（如2026-01）',
  `bill_year` year DEFAULT NULL COMMENT '账单年份',
  `bill_month` tinyint DEFAULT NULL COMMENT '账单月份',
  `amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '应收金额',
  `paid_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '已付金额',
  `discount_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '减免金额',
  `overdue_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '滞纳金',
  `total_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '总金额(含滞纳金)',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1未缴 2部分缴纳 3已缴清 4已减免',
  `due_date` date DEFAULT NULL COMMENT '缴费截止日期',
  `pay_date` datetime DEFAULT NULL COMMENT '缴费完成日期',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  `dunning_time` datetime DEFAULT NULL COMMENT '最近催单时间',
  `dunning_count` int unsigned NOT NULL DEFAULT '0' COMMENT '催单次数',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_bill_no` (`bill_no`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_owner_id` (`owner_id`) USING BTREE,
  KEY `idx_room_id` (`room_id`) USING BTREE,
  KEY `idx_charge_item_id` (`charge_item_id`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE,
  KEY `idx_due_date` (`due_date`) USING BTREE,
  KEY `idx_bill_period` (`bill_period`) USING BTREE,
  KEY `idx_delete_time` (`delete_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=73 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='账单';
/*!40101 SET character_set_client = @saved_cs_client */;

