CREATE TABLE `ds_bill_dunning` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `room_id` int unsigned NOT NULL DEFAULT '0' COMMENT '房间ID',
  `owner_id` int unsigned NOT NULL DEFAULT '0' COMMENT '业主ID',
  `total_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '应收总额',
  `paid_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '已付总额',
  `arrears_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '欠费总额',
  `bill_count` int NOT NULL DEFAULT '0' COMMENT '关联账单数',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL DEFAULT '' COMMENT '备注',
  `channel` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT 'manual',
  `admin_id` int unsigned NOT NULL DEFAULT '0' COMMENT '操作人',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `delete_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_room_id` (`room_id`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_owner_id` (`owner_id`) USING BTREE,
  KEY `idx_create_time` (`create_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='催单记录';
