--
-- Table structure for table `ds_bill_payment`
--

DROP TABLE IF EXISTS `ds_bill_payment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_bill_payment` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `payment_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '缴费单号',
  `bill_id` bigint unsigned NOT NULL DEFAULT '0' COMMENT '账单ID',
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `owner_id` int unsigned NOT NULL DEFAULT '0' COMMENT '业主ID',
  `room_id` int unsigned NOT NULL DEFAULT '0' COMMENT '房间ID',
  `amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '缴费金额',
  `pay_method` tinyint(1) NOT NULL DEFAULT '1' COMMENT '支付方式 1现金 2微信 3支付宝 4银行转账 5pos刷卡 6其他',
  `pay_account` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '付款账户',
  `trade_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '交易流水号',
  `pay_time` datetime DEFAULT NULL COMMENT '支付时间',
  `operator_id` int unsigned NOT NULL DEFAULT '0' COMMENT '操作员ID（物业员工）',
  `operator_type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '操作员类型 1管理员 2物业员工',
