CREATE TABLE `ds_building` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '楼栋名称（如A栋、1号楼）',
  `unit_count` int NOT NULL DEFAULT '1' COMMENT '单元数',
  `floor_count` int NOT NULL DEFAULT '1' COMMENT '层数',
  `floor_rooms` int NOT NULL DEFAULT '0' COMMENT '每层户数',
  `has_commercial` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否有底商',
  `commercial_floors` int NOT NULL DEFAULT '0' COMMENT '底商层数',
  `total_rooms` int NOT NULL DEFAULT '0' COMMENT '总户数',
  `manager_id` int unsigned NOT NULL DEFAULT '0' COMMENT '楼栋管理员',
  `build_year` year DEFAULT NULL COMMENT '建造年份',
  `elevator_count` int NOT NULL DEFAULT '0' COMMENT '电梯数量',
  `floor_height` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '层高(米)',
  `sort` int NOT NULL DEFAULT '0' COMMENT '排序',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1正常 0停用',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_community_building` (`community_id`,`name`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE,
  KEY `idx_delete_time` (`delete_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=110 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='楼栋';
