DROP TABLE IF EXISTS `ds_charge_item`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_charge_item` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '收费项目名称',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '收费项目编码',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '收费类型 1周期性收费 2固定费用 3抄表收费 4押金 5滞纳金',
  `cycle` tinyint(1) NOT NULL DEFAULT '1' COMMENT '周期 1月 2季 3半年 4年',
  `billing_mode` tinyint(1) NOT NULL DEFAULT '1' COMMENT '计费模式 1按面积 2按户 3按人数 4按用量 5固定金额',
  `unit_price` decimal(10,4) NOT NULL DEFAULT '0.0000' COMMENT '单价',
  `unit` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '单位（元/㎡/月, 元/户/月等）',
  `overdue_rate` decimal(5,4) NOT NULL DEFAULT '0.0000' COMMENT '滞纳金日费率(千分之)',
  `overdue_days` int NOT NULL DEFAULT '0' COMMENT '免滞纳金天数',
  `tax_rate` decimal(5,2) NOT NULL DEFAULT '0.00' COMMENT '税率(%)',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1启用 0停用',
  `sort` int NOT NULL DEFAULT '0' COMMENT '排序',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_code` (`code`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_type` (`type`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE,
  KEY `idx_delete_time` (`delete_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='收费项目';
