DROP TABLE IF EXISTS `ds_complaint`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_complaint` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `complaint_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '投诉编号',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '标题',
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `owner_id` int unsigned NOT NULL DEFAULT '0' COMMENT '业主ID',
  `room_id` int unsigned NOT NULL DEFAULT '0' COMMENT '房间ID',
  `complaint_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '投诉人姓名',
  `complaint_phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '联系电话',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类型 1投诉 2建议 3表扬 4咨询',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '分类 环境/服务/噪音/宠物/装修/其他',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '投诉/建议内容',
  `images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '图片（JSON）',
  `handler_id` int unsigned NOT NULL DEFAULT '0' COMMENT '处理人ID',
  `handler_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '处理人',
  `handle_time` datetime DEFAULT NULL COMMENT '处理时间',
  `handle_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '处理内容',
  `handle_images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '处理图片',
  `rating` tinyint(1) NOT NULL DEFAULT '0' COMMENT '满意度评分 1-5',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1待处理 2处理中 3已处理 4已关闭 5已评价',
  `is_public` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否公开 0否 1是',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_complaint_no` (`complaint_no`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_owner_id` (`owner_id`) USING BTREE,
  KEY `idx_type` (`type`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE,
  KEY `idx_create_time` (`create_time`) USING BTREE,
  KEY `idx_delete_time` (`delete_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=27 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='投诉建议';
/*!40101 SET character_set_client = @saved_cs_client */;

