INSERT INTO `ds_complaint` VALUES (1,'DSC202606020001','1号楼电梯异响严重',8,15,713,'王大伟','13900001001',1,'0','1号楼电梯运行时发出巨大异响，已经持续三天了，老人小孩都不敢乘坐，希望尽快维修！','[]',0,'',NULL,'',NULL,0,1,1,'','2026-06-01 08:30:00','2026-06-03 02:38:46',NULL),(2,'DSC202606020002','小区南门快递乱堆放',8,16,714,'李芳','13900001002',1,'0','南门快递点长期堆放大量包裹，影响小区美观，而且刮风天包裹到处飞，建议设置统一快递柜。','[]',0,'',NULL,'',NULL,0,1,1,'','2026-06-01 10:15:00','2026-06-03 02:38:46',NULL),(3,'DSC202606020003','建议增设健身器材',8,17,715,'张建国','13900001003',2,'0','小区广场缺少健身器材，很多老年人只能在路边活动，建议在广场加装太极揉推器、漫步机等器材。','[]',0,'',NULL,'',NULL,0,1,1,'','2026-06-01 14:00:00','2026-06-03 02:38:46',NULL),(4,'DSC202606020004','感谢保安李师傅帮我找到走失宠物',8,18,716,'刘美华','13900001004',3,'0','6月1日我家小狗走失，保安李师傅调取监控、发动大家帮忙寻找，半小时内就找到了，非常感动！','[]',1,'赵建国','2026-06-05 14:42:53','好的',NULL,0,2,1,'','2026-06-02 09:00:00','2026-06-05 14:42:53',NULL),(5,'DSC202606020005','3栋楼下停车位被占用',8,21,719,'黄小刚','13900001007',1,'0','我的固定车位A56经常被外来车辆占用，跟物业反映多次没有改善，严重影响出行。','[]',1,'赵建国','2026-06-05 14:42:45','已清理',NULL,0,2,0,'','2026-06-02 16:45:00','2026-06-05 14:42:45',NULL),(6,'DSC202606020006','装修噪音扰民',8,19,717,'陈志强','13900001005',1,'0','隔壁1803周末早上7点就开始装修，电钻声持续不断，严重影响休息。希望物业能规范装修时间。','[]',1,'赵建国','2026-06-05 14:42:27','已停止',NULL,0,2,1,'','2026-06-03 07:20:00','2026-06-05 14:42:27',NULL),(7,'DSC202606020007','2号楼垃圾桶异味严重',8,20,718,'杨丽萍','13900001006',1,'0','2号楼楼下垃圾桶已经四天没清理了，夏天到了气味非常难闻，蚊虫滋生。','[]',1,'admin','2026-05-31 09:30:00','',NULL,0,2,1,'','2026-05-30 08:00:00','2026-06-03 02:38:46',NULL),(8,'DSC202606020008','小区路灯多盏不亮',8,15,713,'王大伟','13900001001',1,'0','5号楼到南门之间的路灯有5盏不亮，晚上走路很危险，尤其是老人和小孩。','[]',1,'admin','2026-05-30 14:00:00','',NULL,0,2,1,'','2026-05-29 19:30:00','2026-06-03 02:38:46',NULL),(9,'DSC202606020009','建议组织端午节社区活动',8,18,716,'刘美华','13900001004',2,'0','端午节快到了，建议物业组织包粽子活动，增进邻里感情。可以提供场地和材料。','[]',1,'赵建国','2026-06-05 14:43:45','完结',NULL,0,3,1,'','2026-05-28 11:00:00','2026-06-05 14:43:45',NULL),(10,'DSC202606020010','地下车库漏水',8,21,719,'黄小刚','13900001007',1,'0','地下车库B区天花板漏水，我的车被淋得全是泥水，希望尽快修复。','[]',1,'admin','2026-05-28 15:00:00','已安排工程部检查，发现是排水管堵塞导致。已疏通并修复天花板，后续每季度检查一次。',NULL,0,3,1,'','2026-05-26 09:00:00','2026-06-03 02:38:46',NULL),(11,'DSC202606020011','表扬保洁员张阿姨工作认真',8,16,714,'李芳','13900001002',3,'0','保洁张阿姨负责楼栋卫生，工作非常认真负责，楼道扶手擦得干干净净，希望物业给予表扬。','[]',1,'admin','2026-05-27 10:00:00','已收到表扬，已向保洁部传达，会对张阿姨进行嘉奖。',NULL,0,3,1,'','2026-05-25 08:30:00','2026-06-03 02:38:46',NULL),(12,'DSC202606020012','建议增加电动车充电桩',8,17,715,'张建国','13900001003',2,'0','小区电动车越来越多，充电桩严重不足，经常排队很久。建议在3号楼和5号楼旁各增设一排充电桩。','[]',1,'admin','2026-05-25 11:00:00','已采纳建议，已联系供应商进行方案评估。预计下月初在3号楼旁安装5个充电桩。',NULL,0,3,1,'','2026-05-22 14:00:00','2026-06-03 02:38:46',NULL),(13,'DSC202606020013','投诉邻里噪音问题',8,19,717,'陈志强','13900001005',1,'0','楼上每天晚上10点后还在放音乐，声音很大，严重干扰休息。','[]',1,'admin','2026-05-20 09:00:00','已上门沟通，楼上业主承诺晚上9点半后不会再放音乐。如后续再有噪音请及时反馈。',NULL,0,4,0,'','2026-05-18 22:30:00','2026-06-03 02:38:46',NULL),(14,'DSC202606020014','小区门禁系统故障',8,20,718,'杨丽萍','13900001006',1,'0','小区北门门禁系统频繁故障，经常刷不开门，访客来访很不方便。','[]',2,'小区管理员','2026-06-07 15:46:08','已处理',NULL,5,3,1,'','2026-05-12 08:00:00','2026-06-07 15:46:08',NULL),(15,'DSC202606020015','A栋外墙脱落',9,22,738,'赵文博','13900002001',1,'0','A栋外墙瓷砖出现松动脱落现象，楼下是行人通道，存在严重安全隐患！请尽快处理。','[]',0,'',NULL,'',NULL,0,1,1,'','2026-06-02 08:00:00','2026-06-03 02:38:46',NULL),(16,'DSC202606020016','建议设置儿童游乐区',9,23,739,'周晓燕','13900002002',2,'0','翠苑新城缺少儿童游乐设施，很多小朋友只能在停车道上玩耍，非常危险。建议在花园空地设置儿童游乐区。','[]',0,'',NULL,'',NULL,0,1,1,'','2026-06-02 15:00:00','2026-06-03 02:38:46',NULL),(17,'DSC202606020017','咨询物业费调整事宜',9,25,742,'徐春梅','13900002004',4,'0','听说物业费要涨价，想具体了解涨价幅度和从什么时候开始执行，是否有听证会？','[]',0,'',NULL,'',NULL,0,1,0,'','2026-06-01 11:30:00','2026-06-03 02:38:46',NULL),(18,'DSC202606020018','表扬维修师傅王工',9,24,741,'吴建国','13900002003',3,'0','上周我家水管爆裂，王工深夜赶来抢修，技术娴熟态度好，不到一小时就修好了，十分感谢。','[]',0,'',NULL,'',NULL,0,1,1,'','2026-06-03 10:00:00','2026-06-03 02:38:46',NULL),(19,'DSC202606020019','小区绿化浇水时间不合理',9,22,738,'赵文博','13900002001',2,'0','绿化浇水总是在上班早高峰进行，路边全是水，走路容易打滑。建议改到下午5点后浇水。','[]',0,'',NULL,'',NULL,0,1,1,'','2026-06-02 07:00:00','2026-06-03 02:38:46',NULL),(20,'DSC202606020020','地库入口坡道太陡',9,23,739,'周晓燕','13900002002',1,'0','地库入口坡道设计太陡，下雨天地上特别滑，我的车已经蹭底盘两次了。','[]',1,'admin','2026-05-30 10:00:00','',NULL,0,2,1,'','2026-05-29 16:00:00','2026-06-03 02:38:46',NULL),(21,'DSC202606020021','建议小区引入共享药箱',9,25,742,'徐春梅','13900002004',2,'0','建议在物业服务中心设立共享药箱，让居民把多余的非临期药品分享出来，应急时方便邻里。','[]',1,'admin','2026-05-28 09:00:00','',NULL,0,2,1,'','2026-05-27 10:30:00','2026-06-03 02:38:46',NULL),(22,'DSC202606020022','门卫态度差投诉',9,24,741,'吴建国','13900002003',1,'0','上周有快递员进小区，门卫赵师傅态度恶劣，当着很多人的面大声呵斥快递员，影响小区形象。','[]',1,'admin','2026-05-25 16:00:00','已约谈赵师傅，进行了批评教育。赵师傅认识到错误并承诺改进服务态度。',NULL,0,3,0,'','2026-05-23 14:00:00','2026-06-03 02:38:46',NULL),(23,'DSC202606020023','提议增设社区图书馆',9,22,738,'赵文博','13900002001',2,'0','建议利用物业服务中心闲置房间改造成社区图书馆/阅览室，丰富居民文化生活。可以捐赠部分书籍。','[]',1,'admin','2026-05-22 10:00:00','感谢建议，已向业委会提议。闲置房间需进行改造预算评估，预计三季度启动方案讨论。',NULL,0,3,1,'','2026-05-20 09:00:00','2026-06-03 02:38:46',NULL),(24,'DSC202606020024','楼道杂物堆积',9,23,739,'周晓燕','13900002002',1,'0','9楼楼道堆满鞋柜和杂物，消防通道完全堵塞，一旦发生火灾后果不堪设想。','[]',1,'admin','2026-05-18 11:00:00','已联系9楼业主清理楼道杂物，消防通道恢复畅通。已张贴通知提醒全体居民。',NULL,0,4,0,'','2026-05-16 09:00:00','2026-06-03 02:38:46',NULL),(25,'DSC202606020025','下水道反水问题',9,25,742,'徐春梅','13900002004',1,'0','厨房下水道频繁反水，味道非常臭，清理过几次都没用。','[]',1,'admin','2026-05-10 15:00:00','已安排专业疏通公司进行全面疏通，更换了老化管道，问题已彻底解决。',NULL,4,5,1,'','2026-05-08 18:00:00','2026-06-03 02:38:46',NULL),(26,'DSC202606041839575839','测试业主端',12,230,0,'丁亿','17771200068',1,'','测试业主端',NULL,1,'超级管理员','2026-06-04 18:57:33','测试中，',NULL,0,3,0,'','2026-06-04 18:39:57','2026-06-04 18:57:33',NULL);
