--
-- Table structure for table `ds_elevator`
--

DROP TABLE IF EXISTS `ds_elevator`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_elevator` (
  `id` int NOT NULL AUTO_INCREMENT,
  `community_id` int NOT NULL,
  `building_id` int NOT NULL COMMENT '所在楼栋',
  `elevator_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '电梯编号',
  `elevator_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '类型',
  `brand` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '品牌',
  `model` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '型号',
  `serial_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '出厂编号',
  `floor_count` int DEFAULT '0' COMMENT '停靠层数',
  `speed` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '速度',
  `capacity` int DEFAULT '0' COMMENT '载重',
  `install_date` date DEFAULT NULL COMMENT '安装日期',
  `last_inspection_date` date DEFAULT NULL COMMENT '最近年检',
  `next_inspection_date` date DEFAULT NULL COMMENT '下次年检',
  `maintain_company` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '维保公司',
  `maintain_phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '维保电话',
  `contract_start` date DEFAULT NULL COMMENT '合同开始',
  `contract_end` date DEFAULT NULL COMMENT '合同结束',
  `status` tinyint(1) DEFAULT '1' COMMENT '1正常2检修3故障4停用5报废',
  `running_status` tinyint(1) DEFAULT '1' COMMENT '1运行中2停止3异常',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci,
  `create_time` datetime DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  `delete_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_elevator_no` (`elevator_no`) USING BTREE,
  KEY `idx_building` (`building_id`) USING BTREE,
  KEY `idx_inspection` (`next_inspection_date`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=13 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='电梯台账表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `ds_elevator`
--

