DROP TABLE IF EXISTS `ds_elevator_fault`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_elevator_fault` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `elevator_id` int NOT NULL,
  `fault_time` datetime DEFAULT NULL COMMENT '故障时间',
  `fault_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '故障类型',
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '故障描述',
  `is_trapped` tinyint(1) DEFAULT '0' COMMENT '是否困人',
  `trapped_persons` int DEFAULT '0' COMMENT '被困人数',
  `rescue_time` datetime DEFAULT NULL COMMENT '解救时间',
  `repair_company` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '维修单位',
  `repair_person` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '维修人',
  `repair_time` datetime DEFAULT NULL COMMENT '维修完成时间',
  `repair_result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '维修结果',
  `cost` decimal(10,2) DEFAULT '0.00' COMMENT '维修费用',
  `status` tinyint(1) DEFAULT '1' COMMENT '1待维修2维修中3已修复',
  `create_time` datetime DEFAULT NULL,
  `delete_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_elevator` (`elevator_id`) USING BTREE,
  KEY `idx_fault_time` (`fault_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=17 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='电梯故障记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

