  `inspection_date` date DEFAULT NULL COMMENT '检查日期',
  `inspector` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '检查人',
  `inspection_company` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '检查单位',
  `result` tinyint(1) DEFAULT '1' COMMENT '1合格2不合格3需整改',
