DROP TABLE IF EXISTS `ds_equipment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_equipment` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `category` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类别 1电梯 2消防 3安防 4照明 5给排水 6供电 7燃气 8空调 9其他',
  `name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '设备名称',
  `code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '设备编号',
  `model` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '型号',
  `brand` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '品牌',
  `manufacturer` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '生产厂家',
  `spec` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '规格参数',
  `location` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '安装位置',
  `purchase_date` date DEFAULT NULL COMMENT '购买日期',
  `install_date` date DEFAULT NULL COMMENT '安装日期',
  `warranty_expire` date DEFAULT NULL COMMENT '保修截止',
  `service_life` int NOT NULL DEFAULT '0' COMMENT '使用寿命(年)',
  `maintain_cycle` int NOT NULL DEFAULT '0' COMMENT '维保周期(天)',
  `last_maintain_date` date DEFAULT NULL COMMENT '上次维保日期',
  `next_maintain_date` date DEFAULT NULL COMMENT '下次维保日期',
  `supplier` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '供应商',
