--
-- Table structure for table `ds_equipment_maintain`
--

DROP TABLE IF EXISTS `ds_equipment_maintain`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_equipment_maintain` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `equipment_id` int unsigned NOT NULL DEFAULT '0' COMMENT '设备ID',
  `equipment_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '设备名称',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类型 1日常巡检 2定期维保 3故障维修 4紧急抢修',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '维保内容',
  `maintainer` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '维保人员',
  `maintain_company` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '维保公司',
  `cost` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '维保费用',
  `maintain_date` date NOT NULL COMMENT '维保日期',
  `next_maintain_date` date DEFAULT NULL COMMENT '下次维保日期',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1已完成 2待确认 3异常',
  `result` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '维保结果',
  `attachments` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '附件（JSON）',
  `operator_id` int unsigned NOT NULL DEFAULT '0' COMMENT '操作员ID',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_equipment_id` (`equipment_id`) USING BTREE,
  KEY `idx_maintain_date` (`maintain_date`) USING BTREE,
  KEY `idx_type` (`type`) USING BTREE,
  KEY `idx_delete_time` (`delete_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='设备维保记录';
/*!40101 SET character_set_client = @saved_cs_client */;

