INSERT INTO `ds_equipment_maintain` VALUES (1,8,1,'1号楼客梯',1,'电梯运行平稳无异响，轿厢照明、通风正常，紧急呼叫按钮功能正常，楼层显示准确。门保护装置灵敏可靠。','李建国','奥的斯电梯服务公司',0.00,'2026-05-28','2026-06-10',1,'正常，无需维修',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(2,8,1,'1号楼客梯',2,'更换曳引机润滑油，检查钢丝绳磨损情况（正常），清洁轿厢导轨，检查门机皮带松紧度并调整，测试限速器和安全钳。','李建国','奥的斯电梯服务公司',1500.00,'2026-03-10','2026-06-10',1,'维保完成，各项指标正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(3,8,2,'3号楼货梯',3,'电梯停在5楼不开门，经排查为门机控制器故障，更换门机控制器主板。测试后恢复正常运行。','张伟','通力电梯服务部',3200.00,'2026-05-15','2026-05-30',1,'已修复，运行正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(4,8,3,'消火栓泵1号',2,'检查电机绝缘电阻、轴承温度、联轴器同心度，更换机械密封，清理泵体内部水垢，测试远程启动功能。','陈勇','上海东方泵业',800.00,'2026-01-15','2026-07-15',1,'维保完成，设备运行正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(5,8,4,'消防控制主机',4,'主机报警显示回路故障，3层感烟探测器全部离线。排查发现回路板损坏，紧急更换回路板并重新编程。','王工程师','海湾安全技术公司',5600.00,'2026-05-20','2026-08-20',1,'紧急修复完成，系统恢复正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(6,8,6,'二次供水泵组',1,'检查泵组运行压力（0.38MPa正常），电流正常，无异常振动及噪音，液位控制器工作正常，管路无渗漏。','赵明','南方泵业',0.00,'2026-06-01','2026-06-05',1,'正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(7,8,8,'中央空调主机1号',2,'空调制冷效果下降，检查发现冷媒压力偏低，补充R134a冷媒8kg。压缩机运行参数恢复正常，制冷效果明显改善。','周师傅','约克空调售后中心',2400.00,'2026-04-01','2026-07-01',2,'维修后还需观察一周',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(8,8,8,'中央空调主机1号',3,'上次添加冷媒后运行一周，制冷效果再次下降，经查为蒸发器铜管微漏，需更换蒸发器。已停机待修。','周师傅','约克空调售后中心',800.00,'2026-04-10','2026-04-30',3,'蒸发器需更换，等待配件',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(9,8,9,'小区监控系统',1,'检查各摄像机画面清晰度，3号摄像头画面模糊，清洁镜头后恢复正常。NVR录像存储空间剩余35%，预计还可用60天。','刘工','海康威视代理商',0.00,'2026-06-02','2026-06-15',1,'正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(10,8,10,'垃圾压缩站',2,'更换液压油，检查液压管路密封性，清洁滤网，检查推头及翻转机构润滑情况，更换磨损的密封圈。','吴师傅','中联重科售后',1200.00,'2026-05-01','2026-08-01',1,'维保完成，设备运行良好',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(11,9,11,'A栋乘客电梯',2,'按照GB7588标准进行季度维保：检查导轨润滑情况，更换门滑块，清洁轿顶及底坑，检查钢丝绳张力均匀度，测试应急平层功能。','黄建国','迅达电梯服务公司',1800.00,'2026-04-10','2026-07-10',1,'季度维保完成',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(12,9,12,'喷淋泵1号',1,'巡检：泵体运行正常，压力表指示0.62MPa（正常范围），电机电流42A正常，各阀门位置正确，管路无渗漏。','陈勇','上海凯泉泵业',0.00,'2026-05-30','2026-06-20',1,'正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(13,9,13,'无负压供水设备',2,'检查水泵轴承并加注润滑脂，清洁稳流罐内部，检查压力传感器精度，校准变频器参数。出水压力稳定在0.35MPa。','孙师傅','青岛三利售后',600.00,'2026-04-15','2026-07-15',1,'维保完成',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(14,9,14,'高压开关柜1#',1,'巡检：检查开关柜面板指示正常，真空断路器储能正常，接地刀闸位置正确，无异常放电声和异味。柜内温度32℃正常。','朱工','正泰电气',0.00,'2026-05-25','2027-03-01',1,'正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(15,9,15,'地下车库照明系统',3,'C区地库7盏灯不亮，检查发现线路接头氧化导致接触不良，重新接线并做防水处理，更换2支已烧坏的LED灯管。','张师傅','飞利浦照明经销商',350.00,'2026-05-18','2026-08-01',1,'已修复，照明恢复正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(16,9,16,'门禁管理系统',1,'检查所有门禁控制器在线状态（全部在线），更新2个门禁的人脸库数据。测试5号门禁开门按钮灵敏性正常。','杨技术','中控智慧代理商',0.00,'2026-06-01','2027-01-15',1,'正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(17,9,17,'燃气调压柜',1,'巡检：检查调压柜外观完整无锈蚀，压力表显示3.2kPa正常，紧急切断阀功能正常，法兰连接处无泄漏，周围无杂物堆放。','燃气公司巡检员','燃气公司',0.00,'2026-05-15','2026-12-01',1,'正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(18,9,18,'VRV多联机空调',3,'B栋5楼空调不制冷，排查为室外机压缩机故障（卡缸），更换同型号压缩机，抽真空加氟后试机正常，制冷效果达标。','钟师傅','三星空调售后',8500.00,'2026-03-20','2026-10-10',1,'已修复，制冷恢复正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(19,9,19,'道闸系统',2,'检查道闸电机运行，更换磨损的限位开关，清洁车牌识别摄像头镜头，升级识别软件到最新版本，测试抬杆响应时间<1.5秒。','彭工','捷顺科技',900.00,'2026-03-20','2026-09-20',1,'维保完成',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL),(20,9,20,'小区广播系统',1,'巡检：测试背景音乐播放正常，检查各分区音量均衡，检查7号音箱声音偏小（线路接触不良已修复）。紧急广播切换功能测试正常。','刘工','迪士普音响',0.00,'2026-06-02','2027-01-05',1,'正常',NULL,1,'','2026-06-02 18:50:45','2026-06-02 18:50:45',NULL);
