DROP TABLE IF EXISTS `ds_finance_flow`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_finance_flow` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `flow_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '流水编号',
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类型 1收入 2支出 3退款',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '分类',
  `amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '金额',
  `balance` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '余额',
  `source_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '来源类型 bill/payment/refund/other',
  `source_id` bigint unsigned NOT NULL DEFAULT '0' COMMENT '来源ID',
  `description` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '描述',
  `operator_id` int unsigned NOT NULL DEFAULT '0' COMMENT '操作员ID',
  `operator_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '操作员',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1有效 0作废',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `delete_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_flow_no` (`flow_no`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_type` (`type`) USING BTREE,
  KEY `idx_source_type` (`source_type`) USING BTREE,
  KEY `idx_create_time` (`create_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=43 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='财务流水';
/*!40101 SET character_set_client = @saved_cs_client */;

