DROP TABLE IF EXISTS `ds_gate_config`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_gate_config` (
  `id` int NOT NULL AUTO_INCREMENT,
  `community_id` int NOT NULL DEFAULT '0' COMMENT '小区ID',
  `entrance_name` varchar(100) NOT NULL DEFAULT '' COMMENT '出入口名称',
  `brand` varchar(30) NOT NULL DEFAULT 'generic' COMMENT '品牌标识: jieshun/hikvision/dahua/fuji/hongmen/generic',
  `direction` enum('in','out') NOT NULL DEFAULT 'in' COMMENT '方向',
  `api_url` varchar(500) NOT NULL DEFAULT '' COMMENT 'API地址',
  `api_token` varchar(500) NOT NULL DEFAULT '' COMMENT '认证令牌/密钥',
  `api_username` varchar(100) NOT NULL DEFAULT '' COMMENT '用户名(用于Basic Auth等)',
  `device_sn` varchar(100) NOT NULL DEFAULT '' COMMENT '设备序列号',
  `channel_no` int NOT NULL DEFAULT '1' COMMENT '通道号',
  `enabled` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否启用',
  `remark` varchar(500) NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  `delete_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_community` (`community_id`),
  KEY `idx_brand` (`brand`),
  KEY `idx_device_sn` (`device_sn`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='道闸配置表';
/*!40101 SET character_set_client = @saved_cs_client */;

