  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类型 1水表 2电表 3燃气表',
  `meter_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '表号',
  `previous_reading` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '上次读数',
  `current_reading` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '本次读数',
  `usage_amount` decimal(12,2) NOT NULL DEFAULT '0.00' COMMENT '用量',
  `reading_date` date NOT NULL COMMENT '抄表日期',
  `reading_by` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '抄表人',
  `operator_id` int unsigned NOT NULL DEFAULT '0' COMMENT '操作员ID',
  `photo` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '抄表照片',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1正常 2异常',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_room_id` (`room_id`) USING BTREE,
  KEY `idx_type` (`type`) USING BTREE,
  KEY `idx_reading_date` (`reading_date`) USING BTREE,
  KEY `idx_delete_time` (`delete_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=23 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='抄表读数';
