--
-- Table structure for table `ds_notification`
--

DROP TABLE IF EXISTS `ds_notification`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_notification` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '推送标题',
  `content` text COLLATE utf8mb4_unicode_ci COMMENT '推送内容',
  `target` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '目标人群',
  `type` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'notice' COMMENT '推送类型',
  `priority` tinyint(1) NOT NULL DEFAULT '1' COMMENT '优先级',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态',
  `sent_count` int NOT NULL DEFAULT '0' COMMENT '已发送数',
  `read_count` int NOT NULL DEFAULT '0' COMMENT '已读数',
  `send_time` datetime DEFAULT NULL COMMENT '发送时间',
