--
-- Table structure for table `ds_parking_fee_rule`
--

DROP TABLE IF EXISTS `ds_parking_fee_rule`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_parking_fee_rule` (
  `id` int NOT NULL AUTO_INCREMENT,
  `community_id` int NOT NULL,
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '规则名称',
  `vehicle_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '适用车型',
  `charge_type` tinyint(1) DEFAULT '1' COMMENT '1按时2按次3按月4免费',
  `free_minutes` int DEFAULT '30' COMMENT '免费时长',
  `unit_price` decimal(10,2) DEFAULT '0.00' COMMENT '单价',
  `unit_duration` int DEFAULT '60' COMMENT '计价单位',
  `daily_max` decimal(10,2) DEFAULT '0.00' COMMENT '每日封顶',
  `monthly_price` decimal(10,2) DEFAULT '0.00' COMMENT '月租价格',
  `night_free` tinyint(1) DEFAULT '0' COMMENT '夜间免费',
  `night_start` varchar(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '22:00' COMMENT '夜间开始',
  `night_end` varchar(5) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '08:00' COMMENT '夜间结束',
  `status` tinyint(1) DEFAULT '1',
  `create_time` datetime DEFAULT NULL,
  `update_time` datetime DEFAULT NULL,
  `delete_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=66 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='停车费率规则表';
/*!40101 SET character_set_client = @saved_cs_client */;

