--
-- Table structure for table `ds_parking_payment`
--

DROP TABLE IF EXISTS `ds_parking_payment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_parking_payment` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `community_id` int NOT NULL,
  `vehicle_id` int DEFAULT '0' COMMENT '车辆ID',
  `plate_no` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '车牌',
  `payment_type` tinyint(1) DEFAULT '1' COMMENT '1临时缴费2月租续费3包年',
  `pay_method` tinyint(1) DEFAULT '0' COMMENT '支付方式',
  `amount` decimal(10,2) DEFAULT '0.00' COMMENT '金额',
  `duration_months` int DEFAULT '0' COMMENT '续费月数',
  `period_start` date DEFAULT NULL COMMENT '有效期起',
  `period_end` date DEFAULT NULL COMMENT '有效期止',
  `pay_time` datetime DEFAULT NULL,
  `trade_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '' COMMENT '交易号',
  `operator_id` int DEFAULT '0',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci,
  `create_time` datetime DEFAULT NULL,
  `delete_time` datetime DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_plate` (`plate_no`) USING BTREE,
  KEY `idx_vehicle` (`vehicle_id`) USING BTREE,
  KEY `idx_time` (`pay_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=43 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC COMMENT='停车缴费记录表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `ds_parking_payment`
--

LOCK TABLES `ds_parking_payment` WRITE;
/*!40000 ALTER TABLE `ds_parking_payment` DISABLE KEYS */;
