--
-- Table structure for table `ds_parking_space`
--

DROP TABLE IF EXISTS `ds_parking_space`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_parking_space` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `space_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '车位编号',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类型 1地下 2地面 3立体车库',
  `area` decimal(8,2) NOT NULL DEFAULT '0.00' COMMENT '面积(㎡)',
  `floor` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '所在层',
  `owner_id` int unsigned NOT NULL DEFAULT '0' COMMENT '业主ID（归属）',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1空闲 2已售 3已租 4已用',
  `monthly_fee` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '月租费',
  `start_date` date DEFAULT NULL COMMENT '起租日期',
  `end_date` date DEFAULT NULL COMMENT '到期日期',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_community_space_no` (`community_id`,`space_no`) USING BTREE,
  KEY `idx_owner_id` (`owner_id`) USING BTREE,
