/*!40000 ALTER TABLE `ds_print_template` DISABLE KEYS */;
INSERT INTO `ds_print_template` VALUES (13,'标准缴费收据','receipt_standard','receipt','<div style=\"max-width:800px;margin:0 auto;padding:20px;font-family:SimSun;\">\r\n<h2 style=\"text-align:center;font-size:22px;\">物业管理费收据</h2>\r\n<table style=\"width:100%;border-collapse:collapse;margin-top:20px;\">\r\n<tr><td style=\"padding:8px;\">收款单位：{community_name}物业管理处</td><td style=\"padding:8px;\">日期：{date}</td></tr>\r\n<tr><td style=\"padding:8px;\">交款人：{owner_name}</td><td style=\"padding:8px;\">房号：{room_no}</td></tr>\r\n<tr><td style=\"padding:8px;\">收费项目：{charge_item}</td><td style=\"padding:8px;\">金额：¥{amount}</td></tr>\r\n<tr><td style=\"padding:8px;\">大写金额：{amount_cn}</td><td style=\"padding:8px;\">支付方式：{pay_method}</td></tr>\r\n</table>\r\n<p style=\"margin-top:30px;text-align:right;\">收款人：{cashier}　　盖章：</p>\r\n</div>','A4','portrait',10,10,15,15,1,1,0,'2026-05-15 09:00:00',NULL,NULL),(14,'物业费催缴通知','notice_urge_payment','notice','<div style=\"font-family:SimSun;max-width:700px;padding:20px;\">\r\n<h2 style=\"text-align:center;color:red;\">物业费催缴通知单</h2>\r\n<p><strong>{owner_name}</strong>（{room_no}）业主/住户：</p>\r\n<p>您好！经核查，截至 <strong>{date}</strong>，您名下房屋尚有物业费未缴清：</p>\r\n<table style=\"width:100%;border-collapse:collapse;border:1px solid #333;margin:10px 0;\">\r\n<tr style=\"background:#f5f5f5;\"><td style=\"border:1px solid #333;padding:6px;\">费用期间</td><td style=\"border:1px solid #333;padding:6px;\">应收金额</td><td style=\"border:1px solid #333;padding:6px;\">已缴金额</td><td style=\"border:1px solid #333;padding:6px;\">欠费金额</td></tr>\r\n<tr><td style=\"border:1px solid #333;padding:6px;\">{period}</td><td style=\"border:1px solid #333;padding:6px;\">¥{total}</td><td style=\"border:1px solid #333;padding:6px;\">¥{paid}</td><td style=\"border:1px solid #333;padding:6px;color:red;\">¥{arrears}</td></tr>\r\n</table>\r\n<p>请您在收到本通知后7日内缴纳，逾期将加收滞纳金。</p>\r\n<p style=\"margin-top:30px;\">{community_name}物业管理处</p>\r\n<p>日期：{date}</p>\r\n</div>','A4','portrait',12,12,18,18,0,1,0,'2026-05-16 10:30:00',NULL,NULL),(15,'车辆出入证','form_vehicle_pass','form','<div style=\"font-family:SimSun;max-width:600px;padding:20px;border:3px solid #3498db;\">\r\n<h2 style=\"text-align:center;color:#3498db;\">车辆出入证</h2>\r\n<table style=\"width:100%;margin-top:15px;\">\r\n<tr><td style=\"padding:6px;\">证件编号：{pass_no}</td><td style=\"padding:6px;\">有效期：{valid_date}</td></tr>\r\n<tr><td style=\"padding:6px;\">车主姓名：{owner_name}</td><td style=\"padding:6px;\">联系电话：{phone}</td></tr>\r\n<tr><td style=\"padding:6px;\">房号：{room_no}</td><td style=\"padding:6px;\">车牌号：{plate_no}</td></tr>\r\n<tr><td style=\"padding:6px;\">车辆品牌：{brand}</td><td style=\"padding:6px;\">颜色：{color}</td></tr>\r\n</table>\r\n<p style=\"margin-top:15px;\">说明：请将此证放置于车辆前挡风玻璃处，严禁转借他人使用。</p>\r\n<p style=\"margin-top:20px;text-align:right;\">签发单位：{community_name}管理处</p>\r\n<p style=\"text-align:right;\">签发日期：{date}</p>\r\n</div>','A5','landscape',8,8,12,12,0,1,0,'2026-05-18 14:00:00',NULL,NULL),(16,'物业服务合同','contract_property','contract','<div style=\"font-family:SimSun;max-width:800px;padding:30px;\">\r\n<h1 style=\"text-align:center;\">物业服务合同</h1>\r\n<p style=\"text-align:center;\">合同编号：{contract_no}</p>\r\n<p>甲方（物业服务企业）：<strong>{community_name}物业管理处</strong></p>\r\n<p>乙方（业主）：<strong>{owner_name}</strong>（{room_no}）</p>\r\n<p>根据《物业管理条例》等相关法律法规，甲乙双方就 <strong>{community_name}</strong> 物业管理服务达成如下协议：</p>\r\n<h3>一、物业服务内容</h3>\r\n<p>1. 物业共用部位的维修、养护和管理；</p>\r\n<p>2. 物业共用设施设备的运行、维修、养护和管理；</p>\r\n<p>3. 公共区域清洁卫生、绿化养护、秩序维护。</p>\r\n<h3>二、物业服务费用</h3>\r\n<p>收费标准：<strong>¥{unit_price}元/㎡/月</strong>，建筑面积：<strong>{area}㎡</strong></p>\r\n<p>每月物业费：<strong>¥{monthly_fee}</strong></p>\r\n<p>合同期限：{start_date} 至 {end_date}</p>\r\n<p style=\"margin-top:40px;\">甲方签字：________　　乙方签字：________</p>\r\n<p>日期：{date}</p>\r\n</div>','A4','portrait',15,15,20,20,0,1,0,'2026-05-20 08:30:00',NULL,NULL),(17,'简易收据条','receipt_simple','receipt','<div style=\"font-family:SimSun;padding:15px;border:1px solid #999;\">\r\n<h3 style=\"text-align:center;\">收　据</h3>\r\n<p>兹收到 <strong>{owner_name}</strong>（{room_no}）交来 <strong>{charge_item}</strong></p>\r\n<p>金额：<strong>¥{amount}</strong>（{amount_cn}）</p>\r\n<p style=\"margin-top:20px;\">收款单位：{community_name}　　收款人：{cashier}</p>\r\n<p>日期：{date}</p>\r\n</div>','A5','portrait',8,8,10,10,0,1,0,'2026-05-22 11:00:00',NULL,NULL),(18,'停水停电通知','notice_utility_outage','notice','<div style=\"font-family:SimSun;max-width:700px;padding:20px;border:3px solid #e74c3c;\">\r\n<h2 style=\"text-align:center;color:#e74c3c;\">{outage_type}通知</h2>\r\n<p>尊敬的 <strong>{community_name}</strong> 全体业主/住户：</p>\r\n<p>接相关单位通知，因 <strong>{reason}</strong>，本小区将于以下时段暂停{outage_desc}：</p>\r\n<p style=\"text-align:center;font-size:18px;color:red;\">{outage_time}</p>\r\n<p>请您提前做好相关准备，由此带来的不便敬请谅解。</p>\r\n<p style=\"margin-top:30px;text-align:right;\">{community_name}物业管理处</p>\r\n<p style=\"text-align:right;\">{date}</p>\r\n</div>','A4','portrait',12,10,15,15,0,1,0,'2026-05-25 16:00:00',NULL,NULL),(19,'装修申请表','form_decoration_apply','form','<div style=\"font-family:SimSun;max-width:700px;padding:20px;\">\r\n<h2 style=\"text-align:center;\">装修申请表</h2>\r\n<table style=\"width:100%;margin-top:15px;\">\r\n<tr style=\"background:#f5f5f5;\"><td colspan=\"2\" style=\"padding:8px;font-weight:bold;\">一、申请人信息</td></tr>\r\n<tr><td style=\"padding:6px;\">申请人：{owner_name}</td><td style=\"padding:6px;\">联系电话：{phone}</td></tr>\r\n<tr><td style=\"padding:6px;\">房号：{room_no}</td><td style=\"padding:6px;\">面积：{area}㎡</td></tr>\r\n<tr style=\"background:#f5f5f5;\"><td colspan=\"2\" style=\"padding:8px;font-weight:bold;\">二、装修信息</td></tr>\r\n<tr><td style=\"padding:6px;\">装修单位：{company}</td><td style=\"padding:6px;\">负责人：{contact}</td></tr>\r\n<tr><td style=\"padding:6px;\">装修类型：{deco_type}</td><td style=\"padding:6px;\">工期：{period}</td></tr>\r\n</table>\r\n<h3>三、申请承诺</h3>\r\n<p>本人承诺遵守小区装修管理规定，文明施工，如有违规愿承担相应责任。</p>\r\n<p style=\"margin-top:20px;\">申请人签字：________　　物业审批：________</p>\r\n<p>日期：{date}</p>\r\n</div>','A4','portrait',10,10,15,15,0,1,0,'2026-05-28 09:30:00',NULL,NULL),(20,'电子发票模板','receipt_einvoice','receipt','<div style=\"max-width:700px;border:2px solid #333;padding:20px;font-family:SimSun;\">\r\n<h1 style=\"text-align:center;color:#c00;\">电子发票</h1>\r\n<table style=\"width:100%;margin-top:15px;\">\r\n<tr><td>发票代码：{invoice_code}</td><td>发票号码：{invoice_no}</td></tr>\r\n</table>\r\n<p>购买方：{owner_name}（{room_no}）</p>\r\n<p>销售方：{community_name}物业管理处</p>\r\n<table style=\"width:100%;border-collapse:collapse;margin-top:10px;\">\r\n<tr style=\"border:1px solid #333;\"><td>项目名称</td><td>金额</td></tr>\r\n<tr style=\"border:1px solid #333;\"><td>{charge_item}</td><td>¥{amount}</td></tr>\r\n</table>\r\n<p>合计：¥{amount}（{amount_cn}）</p>\r\n<p style=\"text-align:right;\">开票人：{cashier}　　日期：{date}</p>\r\n</div>','A5','landscape',5,5,8,8,0,1,0,'2026-06-01 10:00:00',NULL,NULL),(21,'临时访客登记表','form_visitor_register','form','<div style=\"font-family:SimSun;max-width:600px;padding:15px;border:2px solid #999;\">\r\n<h3 style=\"text-align:center;\">临时访客登记表</h3>\r\n<table style=\"width:100%;\">\r\n<tr><td>访客姓名：{visitor_name}</td><td>联系电话：{visitor_phone}</td></tr>\r\n<tr><td>证件类型：{id_type}</td><td>证件号码：{id_no}</td></tr>\r\n<tr><td>被访业主：{owner_name}</td><td>房号：{room_no}</td></tr>\r\n<tr><td>来访事由：{reason}</td><td>随行人数：{count}</td></tr>\r\n<tr><td>来访时间：{visit_time}</td><td>离开时间：________</td></tr>\r\n</table>\r\n<p style=\"margin-top:10px;font-size:12px;color:#999;\">注：访客请出示有效证件登记，离开时请签离。</p>\r\n</div>','A4','portrait',10,10,15,15,0,0,0,'2026-06-03 13:00:00',NULL,NULL),(22,'品质巡检表格','form_qa_inspection','other','<div style=\"font-family:SimSun;max-width:700px;padding:20px;\">\r\n<h2 style=\"text-align:center;\">品质巡检表格</h2>\r\n<table style=\"width:100%;border-collapse:collapse;border:1px solid #333;\">\r\n<tr style=\"background:#f0f0f0;\"><th style=\"border:1px solid #333;padding:6px;\">检查项目</th><th style=\"border:1px solid #333;padding:6px;\">检查标准</th><th style=\"border:1px solid #333;padding:6px;\">结果</th><th style=\"border:1px solid #333;padding:6px;\">备注</th></tr>\r\n<tr><td style=\"border:1px solid #333;padding:6px;\">门岗执勤</td><td style=\"border:1px solid #333;padding:6px;\">着装整齐、站姿规范</td><td style=\"border:1px solid #333;padding:6px;\"></td><td style=\"border:1px solid #333;padding:6px;\"></td></tr>\r\n<tr><td style=\"border:1px solid #333;padding:6px;\">巡逻签到</td><td style=\"border:1px solid #333;padding:6px;\">按时完成巡逻路线</td><td style=\"border:1px solid #333;padding:6px;\"></td><td style=\"border:1px solid #333;padding:6px;\"></td></tr>\r\n<tr><td style=\"border:1px solid #333;padding:6px;\">公共区域卫生</td><td style=\"border:1px solid #333;padding:6px;\">地面无垃圾、无异味</td><td style=\"border:1px solid #333;padding:6px;\"></td><td style=\"border:1px solid #333;padding:6px;\"></td></tr>\r\n<tr><td style=\"border:1px solid #333;padding:6px;\">绿化养护</td><td style=\"border:1px solid #333;padding:6px;\">无枯死、修剪及时</td><td style=\"border:1px solid #333;padding:6px;\"></td><td style=\"border:1px solid #333;padding:6px;\"></td></tr>\r\n<tr><td style=\"border:1px solid #333;padding:6px;\">电梯运行</td><td style=\"border:1px solid #333;padding:6px;\">运行正常、无异常声响</td><td style=\"border:1px solid #333;padding:6px;\"></td><td style=\"border:1px solid #333;padding:6px;\"></td></tr>\r\n</table>\r\n<p style=\"margin-top:15px;\">巡查区域：________　　巡查人：________　　日期：{date}</p>\r\n</div>','A4','portrait',10,10,15,15,0,1,0,'2026-06-04 08:00:00',NULL,NULL),(23,'111','111','receipt','1','A4','portrait',10,10,15,15,0,1,0,'2026-06-04 15:01:14',NULL,NULL),(24,'物业服务费缴纳通知单','receipt_fee_notice','receipt','<div style=\"font-family: \'Microsoft YaHei\', \'PingFang SC\', sans-serif; color: #333; max-width: 700px; margin: 0 auto; border: 2px solid #1a73e8; border-radius: 4px; overflow: hidden;\">\r\n  <!-- 头部 -->\r\n  <div style=\"background: linear-gradient(135deg, #1a73e8, #1557b0); padding: 25px 30px; text-align: center;\">\r\n    <div style=\"font-size: 26px; font-weight: bold; color: #fff; letter-spacing: 4px; margin-bottom: 6px;\">物业服务费缴纳通知单</div>\r\n    <div style=\"font-size: 13px; color: rgba(255,255,255,0.85);\">{community_name} 物业管理处</div>\r\n  </div>\r\n  \r\n  <div style=\"padding: 30px;\">\r\n    <!-- 业主信息 -->\r\n    <table style=\"width:100%; border-collapse: collapse; margin-bottom: 25px;\">\r\n      <tr>\r\n        <td style=\"width:15%; padding: 8px 0; font-size: 14px; color: #666;\">房号：</td>\r\n        <td style=\"width:35%; padding: 8px 0; font-size: 15px; font-weight: bold;\">{room_number}</td>\r\n        <td style=\"width:15%; padding: 8px 0; font-size: 14px; color: #666;\">业主姓名：</td>\r\n        <td style=\"width:35%; padding: 8px 0; font-size: 15px; font-weight: bold;\">{owner_name}</td>\r\n      </tr>\r\n      <tr>\r\n        <td style=\"padding: 8px 0; font-size: 14px; color: #666;\">联系电话：</td>\r\n        <td style=\"padding: 8px 0; font-size: 15px;\">{owner_phone}</td>\r\n        <td style=\"padding: 8px 0; font-size: 14px; color: #666;\">建筑面积：</td>\r\n        <td style=\"padding: 8px 0; font-size: 15px;\">{area} ㎡</td>\r\n      </tr>\r\n      <tr>\r\n        <td style=\"padding: 8px 0; font-size: 14px; color: #666;\">缴费周期：</td>\r\n        <td style=\"padding: 8px 0; font-size: 15px;\" colspan=\"3\">{fee_period}</td>\r\n      </tr>\r\n    </table>\r\n    \r\n    <!-- 费用明细 -->\r\n    <div style=\"margin-bottom: 25px;\">\r\n      <div style=\"font-size: 16px; font-weight: bold; color: #1a73e8; border-left: 3px solid #1a73e8; padding-left: 10px; margin-bottom: 12px;\">费用明细</div>\r\n      <table style=\"width:100%; border-collapse: collapse; font-size: 14px;\">\r\n        <thead>\r\n          <tr style=\"background: #f0f5ff;\">\r\n            <th style=\"padding: 10px 12px; border: 1px solid #d0d0d0; text-align: left;\">费用项目</th>\r\n            <th style=\"padding: 10px 12px; border: 1px solid #d0d0d0; text-align: right;\">单价（元/㎡·月）</th>\r\n            <th style=\"padding: 10px 12px; border: 1px solid #d0d0d0; text-align: right;\">计费面积（㎡）</th>\r\n            <th style=\"padding: 10px 12px; border: 1px solid #d0d0d0; text-align: right;\">月数</th>\r\n            <th style=\"padding: 10px 12px; border: 1px solid #d0d0d0; text-align: right;\">金额（元）</th>\r\n          </tr>\r\n        </thead>\r\n        <tbody>\r\n          <tr>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0;\">物业服务费</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">{fee_unit_price}</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">{area}</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">{fee_months}</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right; font-weight: bold;\">{property_fee}</td>\r\n          </tr>\r\n          <tr style=\"background: #fafbfc;\">\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0;\">公共能耗分摊费</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">-</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">-</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">{fee_months}</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">{energy_fee}</td>\r\n          </tr>\r\n          <tr>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0;\">车位管理费</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">-</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">-</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">{fee_months}</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">{parking_fee}</td>\r\n          </tr>\r\n          <tr>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0;\">垃圾清运费</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">-</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">-</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">{fee_months}</td>\r\n            <td style=\"padding: 9px 12px; border: 1px solid #e0e0e0; text-align: right;\">{garbage_fee}</td>\r\n          </tr>\r\n        </tbody>\r\n      </table>\r\n    </div>\r\n    \r\n    <!-- 合计 -->\r\n    <div style=\"background: #f0f5ff; border: 1px solid #c5d5f0; border-radius: 4px; padding: 15px 20px; display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px;\">\r\n      <span style=\"font-size: 16px; color: #333;\">合计金额：</span>\r\n      <span style=\"font-size: 28px; font-weight: bold; color: #e53935;\">¥{total_amount}</span>\r\n      <span style=\"font-size: 13px; color: #888;\">大写：{total_amount_cn}</span>\r\n    </div>\r\n    \r\n    <!-- 缴费信息 -->\r\n    <div style=\"margin-bottom: 25px; padding: 15px; background: #fff8e1; border-radius: 4px; border: 1px solid #ffe082;\">\r\n      <div style=\"font-size: 14px; font-weight: bold; color: #f57c00; margin-bottom: 10px;\">📋 缴费方式</div>\r\n      <table style=\"width:100%; font-size: 13px; color: #555;\">\r\n        <tr><td style=\"padding: 4px 0; width: 80px;\">收款单位：</td><td>{company_name}</td></tr>\r\n        <tr><td style=\"padding: 4px 0;\">开户银行：</td><td>{bank_name}</td></tr>\r\n        <tr><td style=\"padding: 4px 0;\">银行账号：</td><td>{bank_account}</td></tr>\r\n        <tr><td style=\"padding: 4px 0;\">缴费截止：</td><td style=\"color: #e53935; font-weight: bold;\">{due_date}</td></tr>\r\n        <tr><td style=\"padding: 4px 0;\">缴费地点：</td><td>{payment_address}</td></tr>\r\n        <tr><td style=\"padding: 4px 0;\">联系电话：</td><td>{company_phone}</td></tr>\r\n      </table>\r\n    </div>\r\n    \r\n    <!-- 备注 -->\r\n    <div style=\"font-size: 13px; color: #999; line-height: 1.8; margin-bottom: 20px; padding: 12px; background: #f9f9f9; border-radius: 4px;\">\r\n      <strong>温馨提示：</strong><br>\r\n      1. 请于缴费截止日期前完成缴费，逾期将按每日 {late_fee_rate}‰ 收取滞纳金。<br>\r\n      2. 缴费后请妥善保管此通知单及缴费凭证，如有疑问请联系物业服务中心。<br>\r\n      3. 支持现金、银行转账、微信、支付宝等多种支付方式。\r\n    </div>\r\n    \r\n    <!-- 签章区 -->\r\n    <div style=\"display: flex; justify-content: space-between; align-items: flex-end; font-size: 13px; margin-top: 30px;\">\r\n      <div>\r\n        <div style=\"margin-bottom: 8px;\">制单日期：{create_date}</div>\r\n        <div>通知单编号：{bill_number}</div>\r\n      </div>\r\n      <div style=\"text-align: center;\">\r\n        <div style=\"margin-bottom: 40px; font-size: 14px;\">{company_name}</div>\r\n        <div style=\"border-top: 1px solid #333; width: 120px;\">（盖章处）</div>\r\n      </div>\r\n    </div>\r\n  </div>\r\n  \r\n  <!-- 底部 -->\r\n  <div style=\"background: #f5f5f5; padding: 10px 30px; font-size: 11px; color: #999; text-align: center;\">\r\n    本单一式两份，业主与物业各执一份 &nbsp;|&nbsp; 地址：{company_address} &nbsp;|&nbsp; 电话：{company_phone}\r\n  </div>\r\n</div>','A4','portrait',15,15,20,20,0,1,0,'2026-06-04 07:05:21','2026-06-04 07:05:21',NULL),(25,'业主入住欢迎信','notice_welcome','notice','<div style=\"font-family: \'Microsoft YaHei\', \'PingFang SC\', sans-serif; color: #444; max-width: 680px; margin: 0 auto; background: linear-gradient(to bottom, #fff 0%, #fafafa 100%);\">\r\n  <!-- 典雅顶部 -->\r\n  <div style=\"text-align: center; padding: 35px 0 25px; border-bottom: 3px double #c9a96e;\">\r\n    <div style=\"font-size: 12px; color: #c9a96e; letter-spacing: 8px; margin-bottom: 10px;\">WELCOME HOME</div>\r\n    <div style=\"font-size: 28px; font-weight: bold; color: #5d4037; letter-spacing: 6px; margin-bottom: 8px;\">业主入住欢迎信</div>\r\n    <div style=\"width: 60px; height: 2px; background: #c9a96e; margin: 0 auto;\"></div>\r\n  </div>\r\n  \r\n  <div style=\"padding: 30px 20px;\">\r\n    <!-- 称呼 -->\r\n    <div style=\"font-size: 15px; line-height: 2.2; margin-bottom: 25px;\">\r\n      <p style=\"text-indent: 2em;\">尊敬的 <strong style=\"color: #5d4037;\">{owner_name}</strong> 业主：</p>\r\n      <p style=\"text-indent: 2em;\">您好！欢迎您入住 <strong style=\"color: #c9a96e;\">{community_name}</strong>！我们全体物业工作人员对您的到来表示最热烈的欢迎和最诚挚的祝福！</p>\r\n    </div>\r\n    \r\n    <!-- 房屋信息 -->\r\n    <div style=\"background: #fdf8f2; border: 1px solid #e8d5b7; border-radius: 6px; padding: 20px; margin-bottom: 25px;\">\r\n      <div style=\"font-size: 15px; font-weight: bold; color: #5d4037; margin-bottom: 15px; border-left: 3px solid #c9a96e; padding-left: 10px;\">🏠 您的房屋信息</div>\r\n      <table style=\"width:100%; border-collapse: collapse; font-size: 14px;\">\r\n        <tr>\r\n          <td style=\"padding: 6px 0; width: 40%; color: #888;\">房　　号</td>\r\n          <td style=\"padding: 6px 0; font-weight: bold;\">{room_number}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 6px 0; color: #888;\">户　　型</td>\r\n          <td style=\"padding: 6px 0;\">{house_type}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 6px 0; color: #888;\">建筑面积</td>\r\n          <td style=\"padding: 6px 0;\">{area} ㎡</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 6px 0; color: #888;\">交房日期</td>\r\n          <td style=\"padding: 6px 0;\">{delivery_date}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 6px 0; color: #888;\">物业费标准</td>\r\n          <td style=\"padding: 6px 0;\">{fee_unit_price} 元/㎡·月</td>\r\n        </tr>\r\n      </table>\r\n    </div>\r\n    \r\n    <!-- 服务介绍 -->\r\n    <div style=\"margin-bottom: 25px;\">\r\n      <div style=\"font-size: 15px; font-weight: bold; color: #5d4037; margin-bottom: 12px; border-left: 3px solid #c9a96e; padding-left: 10px;\">🌟 物业服务介绍</div>\r\n      <div style=\"font-size: 14px; line-height: 2; color: #666;\">\r\n        <table style=\"width:100%; border-collapse: collapse;\">\r\n          <tr>\r\n            <td style=\"padding: 8px 10px; border-bottom: 1px solid #eee; width: 50%;\">\r\n              <span style=\"color: #c9a96e; margin-right: 8px;\">🏘️</span> 24小时保安巡逻与门禁管理\r\n            </td>\r\n            <td style=\"padding: 8px 10px; border-bottom: 1px solid #eee; width: 50%;\">\r\n              <span style=\"color: #c9a96e; margin-right: 8px;\">🧹</span> 公共区域清洁与绿化养护\r\n            </td>\r\n          </tr>\r\n          <tr>\r\n            <td style=\"padding: 8px 10px; border-bottom: 1px solid #eee;\">\r\n              <span style=\"color: #c9a96e; margin-right: 8px;\">🔧</span> 房屋维修与设施设备维护\r\n            </td>\r\n            <td style=\"padding: 8px 10px; border-bottom: 1px solid #eee;\">\r\n              <span style=\"color: #c9a96e; margin-right: 8px;\">📦</span> 快递代收与便民服务\r\n            </td>\r\n          </tr>\r\n          <tr>\r\n            <td style=\"padding: 8px 10px; border-bottom: 1px solid #eee;\">\r\n              <span style=\"color: #c9a96e; margin-right: 8px;\">🚗</span> 停车管理与车辆登记\r\n            </td>\r\n            <td style=\"padding: 8px 10px; border-bottom: 1px solid #eee;\">\r\n              <span style=\"color: #c9a96e; margin-right: 8px;\">📋</span> 投诉建议快速响应处理\r\n            </td>\r\n          </tr>\r\n          <tr>\r\n            <td style=\"padding: 8px 10px;\">\r\n              <span style=\"color: #c9a96e; margin-right: 8px;\">🎉</span> 社区文化活动组织\r\n            </td>\r\n            <td style=\"padding: 8px 10px;\">\r\n              <span style=\"color: #c9a96e; margin-right: 8px;\">📱</span> 在线报修缴费智慧平台\r\n            </td>\r\n          </tr>\r\n        </table>\r\n      </div>\r\n    </div>\r\n    \r\n    <!-- 联系方式 -->\r\n    <div style=\"background: linear-gradient(135deg, #fdf8f2, #fff); border: 1px solid #e8d5b7; border-radius: 6px; padding: 20px; margin-bottom: 20px;\">\r\n      <div style=\"font-size: 15px; font-weight: bold; color: #5d4037; margin-bottom: 12px;\">📞 常用联系方式</div>\r\n      <table style=\"width:100%; font-size: 14px; color: #555;\">\r\n        <tr>\r\n          <td style=\"padding: 5px 0; width: 50%;\">🏢 物业服务中心</td>\r\n          <td style=\"padding: 5px 0;\">{service_phone}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 5px 0;\">🛡️ 安保值班室（24小时）</td>\r\n          <td style=\"padding: 5px 0;\">{security_phone}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 5px 0;\">🔧 维修报修电话</td>\r\n          <td style=\"padding: 5px 0;\">{repair_phone}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 5px 0;\">📧 投诉建议邮箱</td>\r\n          <td style=\"padding: 5px 0;\">{complaint_email}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 5px 0;\">📍 服务中心地址</td>\r\n          <td style=\"padding: 5px 0;\">{service_address}</td>\r\n        </tr>\r\n      </table>\r\n    </div>\r\n    \r\n    <!-- 祝福语 -->\r\n    <div style=\"text-align: center; padding: 15px 0; font-size: 15px; color: #5d4037; line-height: 2;\">\r\n      <p>再次欢迎您加入{community_name}大家庭！</p>\r\n      <p style=\"font-style: italic; color: #c9a96e;\">我们将竭诚为您提供优质、贴心的物业服务，<br>祝您在这里生活愉快、幸福安康！</p>\r\n    </div>\r\n    \r\n    <!-- 签名 -->\r\n    <div style=\"text-align: right; padding: 20px 0 0; font-size: 14px;\">\r\n      <div style=\"margin-bottom: 5px;\">{company_name}</div>\r\n      <div style=\"margin-bottom: 5px;\">物业管理处</div>\r\n      <div>{create_date}</div>\r\n    </div>\r\n  </div>\r\n</div>','A4','portrait',20,20,25,25,0,1,0,'2026-06-04 07:05:21','2026-06-04 07:05:21',NULL),(26,'物业报修工单','form_repair_order','form','<div style=\"font-family: \'Microsoft YaHei\', \'PingFang SC\', sans-serif; color: #333; max-width: 720px; margin: 0 auto;\">\r\n  \r\n  <!-- 标题栏 -->\r\n  <div style=\"display: flex; align-items: center; margin-bottom: 20px; border-bottom: 4px solid #ff6f00; padding-bottom: 12px;\">\r\n    <div style=\"background: #ff6f00; color: #fff; font-size: 22px; font-weight: bold; padding: 8px 20px; border-radius: 0 4px 4px 0; letter-spacing: 3px;\">物业报修工单</div>\r\n    <div style=\"margin-left: auto; font-size: 13px; color: #999;\">工单编号：{order_number}</div>\r\n  </div>\r\n  \r\n  <div style=\"display: flex; gap: 20px;\">\r\n    <!-- 左列 -->\r\n    <div style=\"flex: 1;\">\r\n      <!-- 基本信息 -->\r\n      <div style=\"border: 1px solid #e0e0e0; border-radius: 4px; margin-bottom: 15px; overflow: hidden;\">\r\n        <div style=\"background: #fff3e0; padding: 10px 15px; font-size: 14px; font-weight: bold; color: #e65100; border-bottom: 1px solid #ffe0b2;\">\r\n          🔍 基本信息\r\n        </div>\r\n        <table style=\"width:100%; font-size: 13px; border-collapse: collapse;\">\r\n          <tr><td style=\"padding: 8px 15px; color: #888; width: 30%; background: #fafafa;\">报修人</td><td style=\"padding: 8px 15px;\">{reporter_name}</td></tr>\r\n          <tr><td style=\"padding: 8px 15px; color: #888; background: #fafafa;\">联系电话</td><td style=\"padding: 8px 15px;\">{reporter_phone}</td></tr>\r\n          <tr><td style=\"padding: 8px 15px; color: #888; background: #fafafa;\">房　　号</td><td style=\"padding: 8px 15px;\">{room_number}</td></tr>\r\n          <tr><td style=\"padding: 8px 15px; color: #888; background: #fafafa;\">报修时间</td><td style=\"padding: 8px 15px;\">{report_time}</td></tr>\r\n          <tr><td style=\"padding: 8px 15px; color: #888; background: #fafafa;\">预约时间</td><td style=\"padding: 8px 15px;\">{appointment_time}</td></tr>\r\n        </table>\r\n      </div>\r\n      \r\n      <!-- 维修分类 -->\r\n      <div style=\"border: 1px solid #e0e0e0; border-radius: 4px; margin-bottom: 15px; overflow: hidden;\">\r\n        <div style=\"background: #fff3e0; padding: 10px 15px; font-size: 14px; font-weight: bold; color: #e65100; border-bottom: 1px solid #ffe0b2;\">\r\n          🏷️ 报修分类\r\n        </div>\r\n        <table style=\"width:100%; font-size: 13px; border-collapse: collapse;\">\r\n          <tr><td style=\"padding: 8px 15px; color: #888; width: 30%; background: #fafafa;\">维修类型</td><td style=\"padding: 8px 15px;\"><span style=\"background: {repair_type_color}; color: #fff; padding: 2px 10px; border-radius: 10px; font-size: 12px;\">{repair_type}</span></td></tr>\r\n          <tr><td style=\"padding: 8px 15px; color: #888; background: #fafafa;\">紧急程度</td><td style=\"padding: 8px 15px;\"><span style=\"background: {urgency_color}; color: #fff; padding: 2px 10px; border-radius: 10px; font-size: 12px;\">{urgency_level}</span></td></tr>\r\n          <tr><td style=\"padding: 8px 15px; color: #888; background: #fafafa;\">维修位置</td><td style=\"padding: 8px 15px;\">{repair_location}</td></tr>\r\n        </table>\r\n      </div>\r\n    </div>\r\n    \r\n    <!-- 右列 -->\r\n    <div style=\"flex: 1;\">\r\n      <!-- 问题描述 -->\r\n      <div style=\"border: 1px solid #e0e0e0; border-radius: 4px; margin-bottom: 15px; overflow: hidden;\">\r\n        <div style=\"background: #fff3e0; padding: 10px 15px; font-size: 14px; font-weight: bold; color: #e65100; border-bottom: 1px solid #ffe0b2;\">\r\n          📝 故障描述\r\n        </div>\r\n        <div style=\"padding: 15px; font-size: 14px; line-height: 1.8; min-height: 100px; background: #fafbfc;\">\r\n          {fault_description}\r\n        </div>\r\n      </div>\r\n      \r\n      <!-- 指派信息 -->\r\n      <div style=\"border: 1px solid #e0e0e0; border-radius: 4px; margin-bottom: 15px; overflow: hidden;\">\r\n        <div style=\"background: #e8f5e9; padding: 10px 15px; font-size: 14px; font-weight: bold; color: #2e7d32; border-bottom: 1px solid #c8e6c9;\">\r\n          👷 派工信息\r\n        </div>\r\n        <table style=\"width:100%; font-size: 13px; border-collapse: collapse;\">\r\n          <tr><td style=\"padding: 8px 15px; color: #888; width: 30%; background: #fafafa;\">维修人员</td><td style=\"padding: 8px 15px; font-weight: bold;\">{worker_name}</td></tr>\r\n          <tr><td style=\"padding: 8px 15px; color: #888; background: #fafafa;\">联系电话</td><td style=\"padding: 8px 15px;\">{worker_phone}</td></tr>\r\n          <tr><td style=\"padding: 8px 15px; color: #888; background: #fafafa;\">派工时间</td><td style=\"padding: 8px 15px;\">{dispatch_time}</td></tr>\r\n        </table>\r\n      </div>\r\n    </div>\r\n  </div>\r\n  \r\n  <!-- 费用 -->\r\n  <div style=\"border: 1px solid #ffcc02; background: #fffde7; border-radius: 4px; padding: 15px; margin-bottom: 15px;\">\r\n    <table style=\"width:100%; font-size: 14px;\">\r\n      <tr>\r\n        <td style=\"width: 25%;\">\r\n          <div style=\"font-size: 12px; color: #888;\">人工费</div>\r\n          <div style=\"font-size: 18px; font-weight: bold; color: #333;\">¥{labor_fee}</div>\r\n        </td>\r\n        <td style=\"width: 25%;\">\r\n          <div style=\"font-size: 12px; color: #888;\">材料费</div>\r\n          <div style=\"font-size: 18px; font-weight: bold; color: #333;\">¥{material_fee}</div>\r\n        </td>\r\n        <td style=\"width: 25%;\">\r\n          <div style=\"font-size: 12px; color: #888;\">费用合计</div>\r\n          <div style=\"font-size: 22px; font-weight: bold; color: #e53935;\">¥{total_fee}</div>\r\n        </td>\r\n        <td style=\"width: 25%;\">\r\n          <div style=\"font-size: 12px; color: #888;\">费用类型</div>\r\n          <div style=\"font-size: 14px; font-weight: bold; color: #333;\">{fee_type}</div>\r\n        </td>\r\n      </tr>\r\n    </table>\r\n  </div>\r\n  \r\n  <!-- 处理记录 -->\r\n  <div style=\"border: 1px solid #e0e0e0; border-radius: 4px; margin-bottom: 15px; overflow: hidden;\">\r\n    <div style=\"background: #e3f2fd; padding: 10px 15px; font-size: 14px; font-weight: bold; color: #1565c0; border-bottom: 1px solid #bbdefb;\">\r\n      🔧 处理记录\r\n    </div>\r\n    <div style=\"padding: 15px; font-size: 13px; line-height: 1.8; min-height: 80px; color: #555;\">\r\n      {process_record}\r\n    </div>\r\n  </div>\r\n  \r\n  <!-- 签字区 -->\r\n  <div style=\"display: flex; justify-content: space-between; margin-top: 25px; font-size: 13px;\">\r\n    <div style=\"text-align: center;\">\r\n      <div style=\"margin-bottom: 30px; color: #888;\">报修人签字</div>\r\n      <div style=\"border-top: 1px solid #333; width: 100px; margin: 0 auto;\"></div>\r\n    </div>\r\n    <div style=\"text-align: center;\">\r\n      <div style=\"margin-bottom: 30px; color: #888;\">维修人员签字</div>\r\n      <div style=\"border-top: 1px solid #333; width: 100px; margin: 0 auto;\"></div>\r\n    </div>\r\n    <div style=\"text-align: center;\">\r\n      <div style=\"margin-bottom: 30px; color: #888;\">物业确认签字</div>\r\n      <div style=\"border-top: 1px solid #333; width: 100px; margin: 0 auto;\"></div>\r\n    </div>\r\n    <div style=\"text-align: center;\">\r\n      <div style=\"margin-bottom: 30px; color: #888;\">日　　期</div>\r\n      <div style=\"border-top: 1px solid #333; width: 100px; margin: 0 auto;\"></div>\r\n    </div>\r\n  </div>\r\n  \r\n  <div style=\"text-align: right; font-size: 11px; color: #bbb; margin-top: 15px; padding-top: 10px; border-top: 1px solid #eee;\">\r\n    {community_name} 物业管理处 &nbsp;|&nbsp; 电话：{service_phone}\r\n  </div>\r\n</div>','A4','portrait',12,12,18,18,0,1,0,'2026-06-04 07:05:21','2026-06-04 07:05:21',NULL),(27,'物业费用年度清单','receipt_annual_statement','receipt','<div style=\"font-family: \'Microsoft YaHei\', \'PingFang SC\', sans-serif; max-width: 720px; margin: 0 auto; color: #333;\">\r\n  \r\n  <!-- 头部 -->\r\n  <div style=\"display: flex; align-items: center; margin-bottom: 20px; padding-bottom: 15px; border-bottom: 2px solid #1565c0;\">\r\n    <div style=\"flex: 1;\">\r\n      <div style=\"font-size: 24px; font-weight: bold; color: #1565c0; letter-spacing: 3px;\">物业费用年度清单</div>\r\n      <div style=\"font-size: 13px; color: #888; margin-top: 5px;\">年度：{year} &nbsp;|&nbsp; {community_name}</div>\r\n    </div>\r\n    <div style=\"text-align: right; font-size: 13px; color: #999;\">\r\n      <div>清单编号：{statement_number}</div>\r\n      <div style=\"margin-top: 3px;\">打印日期：{print_date}</div>\r\n    </div>\r\n  </div>\r\n  \r\n  <!-- 业主信息卡片 -->\r\n  <div style=\"display: flex; gap: 15px; margin-bottom: 25px;\">\r\n    <div style=\"flex: 1; background: linear-gradient(135deg, #e3f2fd, #bbdefb); border-radius: 8px; padding: 18px; color: #0d47a1;\">\r\n      <div style=\"font-size: 12px; opacity: 0.8; margin-bottom: 4px;\">业主</div>\r\n      <div style=\"font-size: 18px; font-weight: bold;\">{owner_name}</div>\r\n      <div style=\"font-size: 12px; margin-top: 4px;\">{owner_phone}</div>\r\n    </div>\r\n    <div style=\"flex: 1; background: linear-gradient(135deg, #e8f5e9, #c8e6c9); border-radius: 8px; padding: 18px; color: #1b5e20;\">\r\n      <div style=\"font-size: 12px; opacity: 0.8; margin-bottom: 4px;\">房号</div>\r\n      <div style=\"font-size: 18px; font-weight: bold;\">{room_number}</div>\r\n      <div style=\"font-size: 12px; margin-top: 4px;\">面积 {area} ㎡</div>\r\n    </div>\r\n    <div style=\"flex: 1; background: linear-gradient(135deg, #fff3e0, #ffe0b2); border-radius: 8px; padding: 18px; color: #e65100;\">\r\n      <div style=\"font-size: 12px; opacity: 0.8; margin-bottom: 4px;\">年缴费合计</div>\r\n      <div style=\"font-size: 22px; font-weight: bold;\">¥{year_total}</div>\r\n      <div style=\"font-size: 12px; margin-top: 4px;\">{paid_status}</div>\r\n    </div>\r\n  </div>\r\n  \r\n  <!-- 月度明细表 -->\r\n  <div style=\"margin-bottom: 25px;\">\r\n    <div style=\"font-size: 16px; font-weight: bold; color: #1565c0; margin-bottom: 12px; border-left: 3px solid #1565c0; padding-left: 10px;\">📊 月度费用明细</div>\r\n    <table style=\"width:100%; border-collapse: collapse; font-size: 13px;\">\r\n      <thead>\r\n        <tr style=\"background: #1565c0; color: #fff;\">\r\n          <th style=\"padding: 9px 10px; text-align: center;\">月份</th>\r\n          <th style=\"padding: 9px 10px; text-align: right;\">物业费</th>\r\n          <th style=\"padding: 9px 10px; text-align: right;\">能耗费</th>\r\n          <th style=\"padding: 9px 10px; text-align: right;\">车位费</th>\r\n          <th style=\"padding: 9px 10px; text-align: right;\">其他</th>\r\n          <th style=\"padding: 9px 10px; text-align: right;\">小计</th>\r\n          <th style=\"padding: 9px 10px; text-align: center;\">状态</th>\r\n        </tr>\r\n      </thead>\r\n      <tbody>\r\n        <tr style=\"background: #fafafa;\">\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: center;\">1月</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m01_property}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m01_energy}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m01_parking}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m01_other}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right; font-weight: bold;\">{m01_total}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: center;\"><span style=\"background: {m01_status_color}; color: #fff; padding: 2px 8px; border-radius: 8px; font-size: 11px;\">{m01_status}</span></td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: center;\">2月</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m02_property}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m02_energy}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m02_parking}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m02_other}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right; font-weight: bold;\">{m02_total}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: center;\"><span style=\"background: {m02_status_color}; color: #fff; padding: 2px 8px; border-radius: 8px; font-size: 11px;\">{m02_status}</span></td>\r\n        </tr>\r\n        <tr style=\"background: #fafafa;\">\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: center;\">3月</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m03_property}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m03_energy}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m03_parking}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right;\">{m03_other}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: right; font-weight: bold;\">{m03_total}</td>\r\n          <td style=\"padding: 8px 10px; border-bottom: 1px solid #e0e0e0; text-align: center;\"><span style=\"background: {m03_status_color}; color: #fff; padding: 2px 8px; border-radius: 8px; font-size: 11px;\">{m03_status}</span></td>\r\n        </tr>\r\n        <!-- 更多月份省略，用 summary 表示 -->\r\n        <tr style=\"background: #e3f2fd; font-weight: bold;\">\r\n          <td style=\"padding: 10px; text-align: center; font-size: 14px;\" colspan=\"2\">年度合计</td>\r\n          <td style=\"padding: 10px; text-align: right; font-size: 14px;\">¥{year_property_total}</td>\r\n          <td style=\"padding: 10px; text-align: right; font-size: 14px;\">¥{year_energy_total}</td>\r\n          <td style=\"padding: 10px; text-align: right; font-size: 14px;\">¥{year_parking_total}</td>\r\n          <td style=\"padding: 10px; text-align: right; font-size: 14px;\">¥{year_other_total}</td>\r\n          <td style=\"padding: 10px; text-align: right; font-size: 18px; color: #e53935;\">¥{year_total}</td>\r\n          <td style=\"padding: 10px; text-align: center;\">-</td>\r\n        </tr>\r\n      </tbody>\r\n    </table>\r\n  </div>\r\n  \r\n  <!-- 备注与签章 -->\r\n  <div style=\"display: flex; justify-content: space-between; align-items: flex-end; margin-top: 25px; padding-top: 15px; border-top: 1px solid #e0e0e0;\">\r\n    <div style=\"font-size: 12px; color: #999; line-height: 1.8;\">\r\n      <div><strong>备注：</strong></div>\r\n      <div>1. 本清单仅作核对参考，以实际缴费凭证为准。</div>\r\n      <div>2. 如有疑问请联系物业服务中心。</div>\r\n      <div>3. 联系电话：{service_phone}</div>\r\n    </div>\r\n    <div style=\"text-align: center;\">\r\n      <div style=\"margin-bottom: 30px; font-size: 14px;\">{company_name}</div>\r\n      <div style=\"border-top: 1px solid #333; width: 120px; padding-top: 3px; font-size: 11px; color: #888;\">（盖章处）</div>\r\n    </div>\r\n  </div>\r\n  \r\n  <div style=\"text-align: center; margin-top: 15px; font-size: 11px; color: #bbb;\">\r\n    {community_name} &nbsp;|&nbsp; 地址：{company_address} &nbsp;|&nbsp; 电话：{service_phone}\r\n  </div>\r\n</div>','A4','portrait',15,15,20,20,0,1,0,'2026-06-04 07:05:21','2026-06-04 07:05:21',NULL),(28,'装修备案登记证','form_decoration_permit','form','<div style=\"font-family: \'Microsoft YaHei\', \'PingFang SC\', sans-serif; max-width: 950px; margin: 0 auto; color: #333;\">\r\n  \r\n  <!-- 双栏布局 -->\r\n  <div style=\"display: flex; gap: 25px;\">\r\n    \r\n    <!-- 左半：证件 -->\r\n    <div style=\"flex: 1; border: 8px double #c62828; border-radius: 4px; padding: 20px; background: #fffef5; position: relative;\">\r\n      <!-- 水印 -->\r\n      <div style=\"position: absolute; top: 50%; left: 50%; transform: translate(-50%,-50%); font-size: 50px; color: rgba(200,200,200,0.15); pointer-events: none; letter-spacing: 10px; white-space: nowrap;\">装修备案</div>\r\n      \r\n      <div style=\"text-align: center; margin-bottom: 18px;\">\r\n        <div style=\"font-size: 10px; color: #c62828; letter-spacing: 6px; margin-bottom: 5px;\">PROPERTY DECORATION PERMIT</div>\r\n        <div style=\"font-size: 24px; font-weight: bold; color: #c62828; letter-spacing: 8px;\">装修备案登记证</div>\r\n        <div style=\"width: 100px; height: 2px; background: #c62828; margin: 8px auto;\"></div>\r\n        <div style=\"font-size: 12px; color: #888;\">{community_name} 物业管理处 签发</div>\r\n      </div>\r\n      \r\n      <table style=\"width:100%; font-size: 13px; border-collapse: collapse;\">\r\n        <tr>\r\n          <td style=\"padding: 8px 0; width: 30%; color: #666;\">备案编号</td>\r\n          <td style=\"padding: 8px 0; font-weight: bold; color: #c62828;\">{permit_number}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 8px 0; color: #666;\">业　　主</td>\r\n          <td style=\"padding: 8px 0; font-weight: bold;\">{owner_name}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 8px 0; color: #666;\">房　　号</td>\r\n          <td style=\"padding: 8px 0; font-weight: bold;\">{room_number}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 8px 0; color: #666;\">装修单位</td>\r\n          <td style=\"padding: 8px 0;\">{company_name}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 8px 0; color: #666;\">负责人</td>\r\n          <td style=\"padding: 8px 0;\">{contact_person}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 8px 0; color: #666;\">联系电话</td>\r\n          <td style=\"padding: 8px 0;\">{contact_phone}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 8px 0; color: #666;\">装修类型</td>\r\n          <td style=\"padding: 8px 0;\"><span style=\"background: #ffcdd2; color: #c62828; padding: 2px 8px; border-radius: 3px; font-size: 12px;\">{decoration_type}</span></td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 8px 0; color: #666;\">有效期限</td>\r\n          <td style=\"padding: 8px 0;\">{start_date} 至 {end_date}</td>\r\n        </tr>\r\n        <tr>\r\n          <td style=\"padding: 8px 0; color: #666;\">施工时间</td>\r\n          <td style=\"padding: 8px 0;\">{work_time}</td>\r\n        </tr>\r\n      </table>\r\n      \r\n      <div style=\"margin-top: 18px; font-size: 11px; color: #999; line-height: 1.8; border-top: 1px dashed #ccc; padding-top: 12px;\">\r\n        <strong style=\"color: #c62828;\">注意事项：</strong><br>\r\n        1. 严格遵守《住宅室内装饰装修管理办法》相关规定。<br>\r\n        2. 施工期间须遵守小区管理规定，不得扰民。<br>\r\n        3. 本证须张贴于装修现场醒目位置，以备查验。<br>\r\n        4. 装修完工后须申请验收，验收合格后退还装修押金。\r\n      </div>\r\n      \r\n      <div style=\"display: flex; justify-content: space-between; margin-top: 20px; font-size: 12px;\">\r\n        <div style=\"text-align: center;\">\r\n          <div style=\"margin-bottom: 25px;\">签发人：{issuer}</div>\r\n          <div style=\"border-top: 1px solid #333; width: 80px; margin: 0 auto; padding-top: 3px;\">签发日期</div>\r\n        </div>\r\n        <div style=\"text-align: center;\">\r\n          <div style=\"margin-bottom: 25px;\">{issue_date}</div>\r\n          <div style=\"border-top: 1px solid #333; width: 80px; margin: 0 auto; padding-top: 3px;\">物业盖章</div>\r\n        </div>\r\n      </div>\r\n    </div>\r\n    \r\n    <!-- 右半：附件信息 -->\r\n    <div style=\"flex: 1;\">\r\n      <!-- 缴费明细 -->\r\n      <div style=\"border: 1px solid #e0e0e0; border-radius: 6px; margin-bottom: 15px; overflow: hidden;\">\r\n        <div style=\"background: #ffebee; padding: 10px 15px; font-size: 14px; font-weight: bold; color: #c62828;\">💰 装修费用明细</div>\r\n        <table style=\"width:100%; font-size: 13px; border-collapse: collapse;\">\r\n          <tr><td style=\"padding: 8px 15px; border-bottom: 1px solid #eee; color: #666;\">装修押金</td><td style=\"padding: 8px 15px; border-bottom: 1px solid #eee; text-align: right; font-weight: bold;\">¥{deposit}</td><td style=\"padding: 8px 10px; border-bottom: 1px solid #eee; text-align: center;\">{deposit_status}</td></tr>\r\n          <tr><td style=\"padding: 8px 15px; border-bottom: 1px solid #eee; color: #666;\">装修管理费</td><td style=\"padding: 8px 15px; border-bottom: 1px solid #eee; text-align: right; font-weight: bold;\">¥{manage_fee}</td><td style=\"padding: 8px 10px; border-bottom: 1px solid #eee; text-align: center;\">{manage_fee_status}</td></tr>\r\n          <tr><td style=\"padding: 8px 15px; border-bottom: 1px solid #eee; color: #666;\">垃圾清运费</td><td style=\"padding: 8px 15px; border-bottom: 1px solid #eee; text-align: right; font-weight: bold;\">¥{garbage_fee}</td><td style=\"padding: 8px 10px; border-bottom: 1px solid #eee; text-align: center;\">{garbage_fee_status}</td></tr>\r\n          <tr style=\"background: #fff3e0;\">\r\n            <td style=\"padding: 10px 15px; font-weight: bold;\">合计</td>\r\n            <td style=\"padding: 10px 15px; text-align: right; font-size: 16px; font-weight: bold; color: #c62828;\">¥{total_fee}</td>\r\n            <td style=\"padding: 10px 10px; text-align: center;\">{total_status}</td>\r\n          </tr>\r\n        </table>\r\n      </div>\r\n      \r\n      <!-- 施工人员 -->\r\n      <div style=\"border: 1px solid #e0e0e0; border-radius: 6px; margin-bottom: 15px; overflow: hidden;\">\r\n        <div style=\"background: #e3f2fd; padding: 10px 15px; font-size: 14px; font-weight: bold; color: #1565c0;\">👷 施工人员登记</div>\r\n        <table style=\"width:100%; font-size: 12px; border-collapse: collapse;\">\r\n          <thead>\r\n            <tr style=\"background: #f5f5f5;\">\r\n              <th style=\"padding: 7px 8px; border-bottom: 1px solid #ddd;\">姓名</th>\r\n              <th style=\"padding: 7px 8px; border-bottom: 1px solid #ddd;\">身份证号</th>\r\n              <th style=\"padding: 7px 8px; border-bottom: 1px solid #ddd;\">工种</th>\r\n              <th style=\"padding: 7px 8px; border-bottom: 1px solid #ddd;\">电话</th>\r\n            </tr>\r\n          </thead>\r\n          <tbody>\r\n            <tr>\r\n              <td style=\"padding: 6px 8px; border-bottom: 1px solid #eee;\">{worker1_name}</td>\r\n              <td style=\"padding: 6px 8px; border-bottom: 1px solid #eee;\">{worker1_id}</td>\r\n              <td style=\"padding: 6px 8px; border-bottom: 1px solid #eee;\">{worker1_type}</td>\r\n              <td style=\"padding: 6px 8px; border-bottom: 1px solid #eee;\">{worker1_phone}</td>\r\n            </tr>\r\n            <tr style=\"background: #fafafa;\">\r\n              <td style=\"padding: 6px 8px; border-bottom: 1px solid #eee;\">{worker2_name}</td>\r\n              <td style=\"padding: 6px 8px; border-bottom: 1px solid #eee;\">{worker2_id}</td>\r\n              <td style=\"padding: 6px 8px; border-bottom: 1px solid #eee;\">{worker2_type}</td>\r\n              <td style=\"padding: 6px 8px; border-bottom: 1px solid #eee;\">{worker2_phone}</td>\r\n            </tr>\r\n            <tr>\r\n              <td style=\"padding: 6px 8px;\">{worker3_name}</td>\r\n              <td style=\"padding: 6px 8px;\">{worker3_id}</td>\r\n              <td style=\"padding: 6px 8px;\">{worker3_type}</td>\r\n              <td style=\"padding: 6px 8px;\">{worker3_phone}</td>\r\n            </tr>\r\n          </tbody>\r\n        </table>\r\n      </div>\r\n      \r\n      <!-- 审批记录 -->\r\n      <div style=\"border: 1px solid #e0e0e0; border-radius: 6px; overflow: hidden;\">\r\n        <div style=\"background: #e8f5e9; padding: 10px 15px; font-size: 14px; font-weight: bold; color: #2e7d32;\">✅ 审批状态</div>\r\n        <table style=\"width:100%; font-size: 13px; border-collapse: collapse;\">\r\n          <tr><td style=\"padding: 7px 15px; border-bottom: 1px solid #eee; width: 35%; color: #666;\">物业审核</td><td style=\"padding: 7px 15px; border-bottom: 1px solid #eee; color: #2e7d32;\">{approval_status}</td></tr>\r\n          <tr><td style=\"padding: 7px 15px; border-bottom: 1px solid #eee; color: #666;\">审核人</td><td style=\"padding: 7px 15px; border-bottom: 1px solid #eee;\">{approver}</td></tr>\r\n          <tr><td style=\"padding: 7px 15px; color: #666;\">审核日期</td><td style=\"padding: 7px 15px;\">{approval_date}</td></tr>\r\n        </table>\r\n      </div>\r\n    </div>\r\n  </div>\r\n</div>','A4','landscape',10,10,20,20,0,1,0,'2026-06-04 07:05:21','2026-06-04 07:05:21',NULL),(29,'阳光花园-收款收据','receipt_YG_standard','receipt','<!DOCTYPE html><html><head><meta charset=\"utf-8\"><style>body{font-family:\'Microsoft YaHei\',sans-serif;margin:0;padding:0}</style></head><body>\r\n<div style=\"max-width:700px;margin:0 auto;border:3px solid #1565c0;border-radius:6px;overflow:hidden;\">\r\n<div style=\"background:linear-gradient(135deg,#1565c0,#0d47a1);padding:18px 25px;text-align:center;\">\r\n<div style=\"font-size:10px;color:rgba(255,255,255,.7);letter-spacing:4px;\">阳光花园 物业管理处</div>\r\n<div style=\"font-size:24px;font-weight:bold;color:#fff;letter-spacing:5px;margin-top:4px;\">收款收据</div>\r\n<div style=\"font-size:10px;color:rgba(255,255,255,.5);margin-top:2px;\">RECEIPT</div></div>\r\n<div style=\"padding:22px 25px;\">\r\n<div style=\"text-align:right;font-size:12px;color:#999;margin-bottom:18px;\">编号:{bill_no} &nbsp;|&nbsp; 日期:{bill_date}</div>\r\n<table style=\"width:100%;border-collapse:collapse;font-size:13px;margin-bottom:16px;\">\r\n<tr><td style=\"padding:5px 0;color:#666;width:18%;\">交款单位/个人</td><td style=\"padding:5px 0;font-weight:bold;border-bottom:1px solid #ddd;\">{payer_name}</td></tr>\r\n<tr><td style=\"padding:5px 0;color:#666;\">房号</td><td style=\"padding:5px 0;border-bottom:1px solid #ddd;\">阳光花园 {room_number}</td></tr>\r\n<tr><td style=\"padding:5px 0;color:#666;\">电话</td><td style=\"padding:5px 0;border-bottom:1px solid #ddd;\">{payer_phone}</td></tr></table>\r\n<table style=\"width:100%;border-collapse:collapse;font-size:13px;margin-bottom:16px;\">\r\n<thead><tr style=\"background:#e3f2fd;\">\r\n<th style=\"padding:8px 8px;border:1px solid #bbb;text-align:left;\">收费项目</th>\r\n<th style=\"padding:8px 8px;border:1px solid #bbb;text-align:right;\">数量</th>\r\n<th style=\"padding:8px 8px;border:1px solid #bbb;text-align:right;\">单价(元)</th>\r\n<th style=\"padding:8px 8px;border:1px solid #bbb;text-align:right;\">金额(元)</th></tr></thead><tbody>\r\n<tr><td style=\"padding:7px 8px;border:1px solid #ddd;\">{fee_item_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_qty_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_price_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_amount_1}</td></tr>\r\n<tr style=\"background:#fafafa;\"><td style=\"padding:7px 8px;border:1px solid #ddd;\">{fee_item_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_qty_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_price_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_amount_2}</td></tr>\r\n<tr><td style=\"padding:7px 8px;border:1px solid #ddd;\">{fee_item_3}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_qty_3}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_price_3}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_amount_3}</td></tr></tbody></table>\r\n<div style=\"background:#e3f2fd;padding:12px 18px;border-radius:4px;margin-bottom:14px;display:flex;justify-content:space-between;align-items:center;\">\r\n<span style=\"font-size:13px;\">合计(大写):{amount_cn}</span>\r\n<span style=\"font-size:22px;font-weight:bold;color:#e53935;\">¥{total_amount}</span></div>\r\n<div style=\"font-size:12px;line-height:1.9;color:#666;margin-bottom:14px;\">\r\n<strong>备注:</strong>{remark}<br><strong>收款方式:</strong>{pay_method} &nbsp;&nbsp;<strong>收款人:</strong>{collector}</div>\r\n<div style=\"display:flex;justify-content:space-between;font-size:12px;margin-top:25px;padding-top:15px;border-top:1px solid #eee;\">\r\n<div style=\"text-align:center;\"><div style=\"margin-bottom:25px;\">收款单位(盖章)</div><div style=\"border-top:1px solid #333;width:90px;margin:0 auto;\"></div></div>\r\n<div style=\"text-align:center;\"><div style=\"margin-bottom:25px;\">经手人</div><div style=\"border-top:1px solid #333;width:70px;margin:0 auto;\"></div></div>\r\n<div style=\"text-align:center;\"><div style=\"margin-bottom:25px;\">交款人</div><div style=\"border-top:1px solid #333;width:70px;margin:0 auto;\"></div></div></div></div>\r\n<div style=\"background:#f5f5f5;padding:8px;text-align:center;font-size:10px;color:#aaa;\">本收据一式两份 &nbsp;|&nbsp; 阳光花园 物业管理处 &nbsp;|&nbsp; 地址:{company_address} &nbsp;|&nbsp; 电话:{service_phone}</div></div></body></html>','A4','portrait',10,10,15,15,1,1,8,'2026-06-04 07:16:59','2026-06-04 07:16:59',NULL),(30,'阳光花园-催缴通知','notice_YG_urge','notice','<!DOCTYPE html><html><head><meta charset=\"utf-8\"><style>body{font-family:\'Microsoft YaHei\',sans-serif;margin:0;padding:0}</style></head><body>\r\n<div style=\"max-width:700px;margin:0 auto;border:3px solid #c62828;border-radius:6px;overflow:hidden;\">\r\n<div style=\"background:#c62828;padding:18px 25px;text-align:center;\">\r\n<div style=\"font-size:22px;font-weight:bold;color:#fff;letter-spacing:5px;\">物业费催缴通知单</div>\r\n<div style=\"font-size:11px;color:rgba(255,255,255,.7);margin-top:4px;\">阳光花园 物业管理处</div></div>\r\n<div style=\"padding:22px 25px;\">\r\n<div style=\"border-left:3px solid #c62828;padding-left:12px;margin-bottom:18px;\">\r\n<div style=\"font-size:13px;color:#c62828;font-weight:bold;\">催缴编号:{urge_no}</div>\r\n<div style=\"font-size:12px;color:#999;\">日期:{urge_date}</div></div>\r\n<div style=\"font-size:14px;line-height:2.3;margin-bottom:18px;\">\r\n<p style=\"text-indent:2em;\">尊敬的 <strong>{owner_name}</strong>(房号:<strong>阳光花园 {room_number}</strong>)业主:</p>\r\n<p style=\"text-indent:2em;\">截至 <strong>{cutoff_date}</strong>,您累计欠缴物业相关费用共计 <strong style=\"color:#c62828;font-size:16px;\">¥{total_arrears}</strong>(大写:{arrears_cn}),具体明细如下:</p></div>\r\n<table style=\"width:100%;border-collapse:collapse;font-size:13px;margin-bottom:16px;\">\r\n<thead><tr style=\"background:#ffebee;\">\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:center;\">序号</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:left;\">费用项目</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:center;\">欠费期间</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:right;\">欠费金额(元)</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:right;\">滞纳金(元)</th></tr></thead><tbody>\r\n<tr><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">1</td><td style=\"padding:7px 8px;border:1px solid #ddd;\">{arrear_item_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">{arrear_period_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{arrear_amount_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{late_fee_1}</td></tr>\r\n<tr style=\"background:#fff5f5;\"><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">2</td><td style=\"padding:7px 8px;border:1px solid #ddd;\">{arrear_item_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">{arrear_period_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{arrear_amount_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{late_fee_2}</td></tr></tbody>\r\n<tfoot><tr style=\"background:#c62828;color:#fff;font-weight:bold;\">\r\n<td style=\"padding:9px 8px;text-align:center;\" colspan=\"3\">合计</td>\r\n<td style=\"padding:9px 8px;text-align:right;font-size:16px;\">¥{total_arrears}</td>\r\n<td style=\"padding:9px 8px;text-align:right;\">¥{total_late_fee}</td></tr></tfoot></table>\r\n<div style=\"background:#fff3e0;border:1px solid #ffcc02;border-radius:6px;padding:14px;margin-bottom:14px;\">\r\n<div style=\"font-size:14px;font-weight:bold;color:#e65100;margin-bottom:10px;\">重要提示</div>\r\n<div style=\"font-size:12px;line-height:2.2;color:#555;\">\r\n1. 请您在收到本通知后 <strong style=\"color:#c62828;\">7日内</strong> 到 阳光花园 物业服务中心结清上述款项。<br>\r\n2. 逾期未缴,滞纳金将按日累计,并可能采取进一步催缴措施。<br>\r\n3. 如已缴纳,请忽略本通知。如有疑问请致电物业服务中心。</div></div>\r\n<div style=\"font-size:12px;color:#555;line-height:2;\">\r\n<strong>缴费地址:</strong>{company_address}<br><strong>联系电话:</strong>{service_phone}<br><strong>收款账户:</strong>{bank_name} {bank_account}</div>\r\n<div style=\"text-align:right;margin-top:20px;font-size:13px;padding-top:15px;border-top:1px solid #eee;\">\r\n<div style=\"margin-bottom:4px;\">阳光花园 物业管理处</div><div>{urge_date}</div></div></div></div></body></html>','A4','portrait',10,10,15,15,0,1,8,'2026-06-04 07:16:59','2026-06-04 07:16:59',NULL),(31,'阳光花园-出入放行条','form_YG_gatepass','form','<!DOCTYPE html><html><head><meta charset=\"utf-8\"><style>body{font-family:\'Microsoft YaHei\',sans-serif;margin:0;padding:0}</style></head><body>\r\n<div style=\"max-width:400px;margin:0 auto;border:3px solid #2e7d32;border-radius:4px;overflow:hidden;background:#f1f8e9;\">\r\n<div style=\"background:#2e7d32;color:#fff;text-align:center;padding:12px 0;\">\r\n<div style=\"font-size:18px;font-weight:bold;letter-spacing:3px;\">阳光花园</div>\r\n<div style=\"font-size:12px;letter-spacing:2px;margin-top:2px;\">车辆/人员 出入放行条</div></div>\r\n<div style=\"padding:12px 15px;\">\r\n<table style=\"width:100%;font-size:13px;border-collapse:collapse;\">\r\n<tr><td style=\"padding:4px 0;color:#555;width:22%;\">编号</td><td style=\"padding:4px 0;font-weight:bold;\">{pass_no}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">放行类型</td><td style=\"padding:4px 0;font-weight:bold;\">{pass_type}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">业主姓名</td><td style=\"padding:4px 0;\">{owner_name}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">房号</td><td style=\"padding:4px 0;\">{room_number}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">联系电话</td><td style=\"padding:4px 0;\">{owner_phone}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">车牌号</td><td style=\"padding:4px 0;font-weight:bold;\">{plate_number}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">携带物品</td><td style=\"padding:4px 0;\">{items}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">有效时间</td><td style=\"padding:4px 0;color:#2e7d32;font-weight:bold;\">{valid_date} {valid_time}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">签发人</td><td style=\"padding:4px 0;\">{issuer}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">签发日期</td><td style=\"padding:4px 0;\">{issue_date}</td></tr></table>\r\n<div style=\"font-size:10px;color:#888;border-top:1px dashed #ccc;padding-top:8px;margin-top:8px;text-align:center;\">请保安核实后放行 &nbsp;|&nbsp; 撕下交保安留存</div></div>\r\n<div style=\"border-top:1px dashed #666;text-align:center;padding:10px 0;font-size:10px;color:#888;margin:0 15px;\">- - - - - - - - - - - - 沿此虚线撕下 - - - - - - - - - - - -</div>\r\n<div style=\"padding:12px 15px;background:#fff;\">\r\n<table style=\"width:100%;font-size:13px;border-collapse:collapse;\">\r\n<tr><td style=\"padding:4px 0;color:#555;width:22%;\">编号</td><td style=\"padding:4px 0;font-weight:bold;\">{pass_no}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">类型</td><td style=\"padding:4px 0;font-weight:bold;\">{pass_type}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">业主</td><td style=\"padding:4px 0;\">{owner_name}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">房号/车牌</td><td style=\"padding:4px 0;\">{room_number} / {plate_number}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">有效期</td><td style=\"padding:4px 0;color:#2e7d32;font-weight:bold;\">{valid_date} {valid_time}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">签发</td><td style=\"padding:4px 0;\">{issuer} / {issue_date}</td></tr></table>\r\n<div style=\"font-size:10px;color:#888;border-top:1px dashed #ccc;padding-top:8px;margin-top:8px;text-align:center;\">此联交业主留存 &nbsp;|&nbsp; 阳光花园 物业</div></div></div></body></html>','A5','portrait',5,5,10,10,0,1,8,'2026-06-04 07:16:59','2026-06-04 07:16:59',NULL),(32,'阳光花园-业主信息登记表','form_YG_ownerinfo','form','<!DOCTYPE html><html><head><meta charset=\"utf-8\"><style>body{font-family:\'Microsoft YaHei\',sans-serif;margin:0;padding:0}</style></head><body>\r\n<div style=\"max-width:700px;margin:0 auto;border:3px solid #4527a0;border-radius:6px;overflow:hidden;\">\r\n<div style=\"background:linear-gradient(135deg,#4527a0,#311b92);padding:18px 25px;text-align:center;\">\r\n<div style=\"font-size:20px;font-weight:bold;color:#fff;letter-spacing:5px;\">业主信息登记表</div>\r\n<div style=\"font-size:11px;color:rgba(255,255,255,.7);margin-top:3px;\">阳光花园 物业管理处</div></div>\r\n<div style=\"padding:18px 22px;\">\r\n<div style=\"background:#ede7f6;padding:12px 14px;border-radius:4px;margin-bottom:12px;\">\r\n<div style=\"font-size:14px;font-weight:bold;color:#4527a0;margin-bottom:8px;\">房屋信息</div>\r\n<table style=\"width:100%;font-size:13px;border-collapse:collapse;\">\r\n<tr><td style=\"padding:4px 0;color:#666;width:20%;\">小区名称</td><td style=\"padding:4px 0;font-weight:bold;\">阳光花园</td><td style=\"padding:4px 0;color:#666;width:20%;\">房号</td><td style=\"padding:4px 0;\">{room_number}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#666;\">户型</td><td style=\"padding:4px 0;\">{house_type}</td><td style=\"padding:4px 0;color:#666;\">建筑面积</td><td style=\"padding:4px 0;\">{area} m2</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#666;\">交付日期</td><td style=\"padding:4px 0;\">{delivery_date}</td><td style=\"padding:4px 0;color:#666;\">入住日期</td><td style=\"padding:4px 0;\">{move_in_date}</td></tr></table></div>\r\n<div style=\"background:#f3e5f5;padding:12px 14px;border-radius:4px;margin-bottom:12px;\">\r\n<div style=\"font-size:14px;font-weight:bold;color:#6a1b9a;margin-bottom:8px;\">业主信息</div>\r\n<table style=\"width:100%;font-size:13px;border-collapse:collapse;\">\r\n<tr><td style=\"padding:4px 0;color:#666;width:20%;\">姓名</td><td style=\"padding:4px 0;\">{owner_name}</td><td style=\"padding:4px 0;color:#666;width:20%;\">性别</td><td style=\"padding:4px 0;\">{owner_gender}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#666;\">身份证号</td><td style=\"padding:4px 0;\">{owner_id_card}</td><td style=\"padding:4px 0;color:#666;\">联系电话</td><td style=\"padding:4px 0;\">{owner_phone}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#666;\">备用电话</td><td style=\"padding:4px 0;\">{owner_phone2}</td><td style=\"padding:4px 0;color:#666;\">邮箱</td><td style=\"padding:4px 0;\">{owner_email}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#666;\">工作单位</td><td style=\"padding:4px 0;\" colspan=\"3\">{owner_company}</td></tr></table></div>\r\n<div style=\"background:#e8eaf6;padding:12px 14px;border-radius:4px;margin-bottom:12px;\">\r\n<div style=\"font-size:14px;font-weight:bold;color:#283593;margin-bottom:8px;\">家庭成员</div>\r\n<table style=\"width:100%;font-size:13px;border-collapse:collapse;\">\r\n<thead><tr style=\"border-bottom:1px solid #c5cae9;\">\r\n<th style=\"padding:5px 8px;text-align:left;\">姓名</th><th style=\"padding:5px 8px;text-align:center;\">关系</th><th style=\"padding:5px 8px;text-align:center;\">电话</th><th style=\"padding:5px 8px;text-align:left;\">备注</th></tr></thead><tbody>\r\n<tr><td style=\"padding:4px 8px;\">{member1_name}</td><td style=\"padding:4px 8px;text-align:center;\">{member1_relation}</td><td style=\"padding:4px 8px;text-align:center;\">{member1_phone}</td><td style=\"padding:4px 8px;\">{member1_remark}</td></tr>\r\n<tr style=\"background:#fafafa;\"><td style=\"padding:4px 8px;\">{member2_name}</td><td style=\"padding:4px 8px;text-align:center;\">{member2_relation}</td><td style=\"padding:4px 8px;text-align:center;\">{member2_phone}</td><td style=\"padding:4px 8px;\">{member2_remark}</td></tr>\r\n<tr><td style=\"padding:4px 8px;\">{member3_name}</td><td style=\"padding:4px 8px;text-align:center;\">{member3_relation}</td><td style=\"padding:4px 8px;text-align:center;\">{member3_phone}</td><td style=\"padding:4px 8px;\">{member3_remark}</td></tr></tbody></table></div>\r\n<div style=\"background:#fff8e1;padding:12px 14px;border-radius:4px;margin-bottom:12px;\">\r\n<div style=\"font-size:14px;font-weight:bold;color:#f57f17;margin-bottom:8px;\">车辆信息</div>\r\n<table style=\"width:100%;font-size:13px;border-collapse:collapse;\">\r\n<thead><tr style=\"border-bottom:1px solid #ffe082;\">\r\n<th style=\"padding:5px 8px;text-align:left;\">车牌号</th><th style=\"padding:5px 8px;text-align:left;\">品牌型号</th><th style=\"padding:5px 8px;text-align:left;\">颜色</th><th style=\"padding:5px 8px;text-align:left;\">车位编号</th></tr></thead><tbody>\r\n<tr><td style=\"padding:4px 8px;\">{car1_plate}</td><td style=\"padding:4px 8px;\">{car1_model}</td><td style=\"padding:4px 8px;\">{car1_color}</td><td style=\"padding:4px 8px;\">{car1_spot}</td></tr>\r\n<tr style=\"background:#fafafa;\"><td style=\"padding:4px 8px;\">{car2_plate}</td><td style=\"padding:4px 8px;\">{car2_model}</td><td style=\"padding:4px 8px;\">{car2_color}</td><td style=\"padding:4px 8px;\">{car2_spot}</td></tr></tbody></table></div>\r\n<div style=\"display:flex;justify-content:space-between;font-size:12px;margin-top:18px;padding-top:12px;border-top:1px solid #eee;\">\r\n<div style=\"text-align:center;\"><div style=\"margin-bottom:25px;\">业主签字</div><div style=\"border-top:1px solid #333;width:80px;margin:0 auto;\"></div></div>\r\n<div style=\"text-align:center;\"><div style=\"margin-bottom:25px;\">登记人</div><div style=\"border-top:1px solid #333;width:80px;margin:0 auto;\"></div></div>\r\n<div style=\"text-align:center;\"><div style=\"margin-bottom:25px;\">日期</div><div style=\"border-top:1px solid #333;width:80px;margin:0 auto;\"></div></div></div></div></div></body></html>','A4','portrait',10,10,15,15,0,1,8,'2026-06-04 07:16:59','2026-06-04 07:16:59',NULL),(33,'翠苑新城-收款收据','receipt_CY_standard','receipt','<!DOCTYPE html><html><head><meta charset=\"utf-8\"><style>body{font-family:\'Microsoft YaHei\',sans-serif;margin:0;padding:0}</style></head><body>\r\n<div style=\"max-width:700px;margin:0 auto;border:3px solid #1565c0;border-radius:6px;overflow:hidden;\">\r\n<div style=\"background:linear-gradient(135deg,#1565c0,#0d47a1);padding:18px 25px;text-align:center;\">\r\n<div style=\"font-size:10px;color:rgba(255,255,255,.7);letter-spacing:4px;\">翠苑新城 物业管理处</div>\r\n<div style=\"font-size:24px;font-weight:bold;color:#fff;letter-spacing:5px;margin-top:4px;\">收款收据</div>\r\n<div style=\"font-size:10px;color:rgba(255,255,255,.5);margin-top:2px;\">RECEIPT</div></div>\r\n<div style=\"padding:22px 25px;\">\r\n<div style=\"text-align:right;font-size:12px;color:#999;margin-bottom:18px;\">编号:{bill_no} &nbsp;|&nbsp; 日期:{bill_date}</div>\r\n<table style=\"width:100%;border-collapse:collapse;font-size:13px;margin-bottom:16px;\">\r\n<tr><td style=\"padding:5px 0;color:#666;width:18%;\">交款单位/个人</td><td style=\"padding:5px 0;font-weight:bold;border-bottom:1px solid #ddd;\">{payer_name}</td></tr>\r\n<tr><td style=\"padding:5px 0;color:#666;\">房号</td><td style=\"padding:5px 0;border-bottom:1px solid #ddd;\">翠苑新城 {room_number}</td></tr>\r\n<tr><td style=\"padding:5px 0;color:#666;\">电话</td><td style=\"padding:5px 0;border-bottom:1px solid #ddd;\">{payer_phone}</td></tr></table>\r\n<table style=\"width:100%;border-collapse:collapse;font-size:13px;margin-bottom:16px;\">\r\n<thead><tr style=\"background:#e3f2fd;\">\r\n<th style=\"padding:8px 8px;border:1px solid #bbb;text-align:left;\">收费项目</th>\r\n<th style=\"padding:8px 8px;border:1px solid #bbb;text-align:right;\">数量</th>\r\n<th style=\"padding:8px 8px;border:1px solid #bbb;text-align:right;\">单价(元)</th>\r\n<th style=\"padding:8px 8px;border:1px solid #bbb;text-align:right;\">金额(元)</th></tr></thead><tbody>\r\n<tr><td style=\"padding:7px 8px;border:1px solid #ddd;\">{fee_item_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_qty_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_price_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_amount_1}</td></tr>\r\n<tr style=\"background:#fafafa;\"><td style=\"padding:7px 8px;border:1px solid #ddd;\">{fee_item_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_qty_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_price_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_amount_2}</td></tr>\r\n<tr><td style=\"padding:7px 8px;border:1px solid #ddd;\">{fee_item_3}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_qty_3}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_price_3}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{fee_amount_3}</td></tr></tbody></table>\r\n<div style=\"background:#e3f2fd;padding:12px 18px;border-radius:4px;margin-bottom:14px;display:flex;justify-content:space-between;align-items:center;\">\r\n<span style=\"font-size:13px;\">合计(大写):{amount_cn}</span>\r\n<span style=\"font-size:22px;font-weight:bold;color:#e53935;\">¥{total_amount}</span></div>\r\n<div style=\"font-size:12px;line-height:1.9;color:#666;margin-bottom:14px;\">\r\n<strong>备注:</strong>{remark}<br><strong>收款方式:</strong>{pay_method} &nbsp;&nbsp;<strong>收款人:</strong>{collector}</div>\r\n<div style=\"display:flex;justify-content:space-between;font-size:12px;margin-top:25px;padding-top:15px;border-top:1px solid #eee;\">\r\n<div style=\"text-align:center;\"><div style=\"margin-bottom:25px;\">收款单位(盖章)</div><div style=\"border-top:1px solid #333;width:90px;margin:0 auto;\"></div></div>\r\n<div style=\"text-align:center;\"><div style=\"margin-bottom:25px;\">经手人</div><div style=\"border-top:1px solid #333;width:70px;margin:0 auto;\"></div></div>\r\n<div style=\"text-align:center;\"><div style=\"margin-bottom:25px;\">交款人</div><div style=\"border-top:1px solid #333;width:70px;margin:0 auto;\"></div></div></div></div>\r\n<div style=\"background:#f5f5f5;padding:8px;text-align:center;font-size:10px;color:#aaa;\">本收据一式两份 &nbsp;|&nbsp; 翠苑新城 物业管理处 &nbsp;|&nbsp; 地址:{company_address} &nbsp;|&nbsp; 电话:{service_phone}</div></div></body></html>','A4','portrait',10,10,15,15,0,1,9,'2026-06-04 07:16:59','2026-06-04 07:16:59',NULL),(34,'翠苑新城-催缴通知','notice_CY_urge','notice','<!DOCTYPE html><html><head><meta charset=\"utf-8\"><style>body{font-family:\'Microsoft YaHei\',sans-serif;margin:0;padding:0}</style></head><body>\r\n<div style=\"max-width:700px;margin:0 auto;border:3px solid #c62828;border-radius:6px;overflow:hidden;\">\r\n<div style=\"background:#c62828;padding:18px 25px;text-align:center;\">\r\n<div style=\"font-size:22px;font-weight:bold;color:#fff;letter-spacing:5px;\">物业费催缴通知单</div>\r\n<div style=\"font-size:11px;color:rgba(255,255,255,.7);margin-top:4px;\">翠苑新城 物业管理处</div></div>\r\n<div style=\"padding:22px 25px;\">\r\n<div style=\"border-left:3px solid #c62828;padding-left:12px;margin-bottom:18px;\">\r\n<div style=\"font-size:13px;color:#c62828;font-weight:bold;\">催缴编号:{urge_no}</div>\r\n<div style=\"font-size:12px;color:#999;\">日期:{urge_date}</div></div>\r\n<div style=\"font-size:14px;line-height:2.3;margin-bottom:18px;\">\r\n<p style=\"text-indent:2em;\">尊敬的 <strong>{owner_name}</strong>(房号:<strong>翠苑新城 {room_number}</strong>)业主:</p>\r\n<p style=\"text-indent:2em;\">截至 <strong>{cutoff_date}</strong>,您累计欠缴物业相关费用共计 <strong style=\"color:#c62828;font-size:16px;\">¥{total_arrears}</strong>(大写:{arrears_cn}),具体明细如下:</p></div>\r\n<table style=\"width:100%;border-collapse:collapse;font-size:13px;margin-bottom:16px;\">\r\n<thead><tr style=\"background:#ffebee;\">\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:center;\">序号</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:left;\">费用项目</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:center;\">欠费期间</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:right;\">欠费金额(元)</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:right;\">滞纳金(元)</th></tr></thead><tbody>\r\n<tr><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">1</td><td style=\"padding:7px 8px;border:1px solid #ddd;\">{arrear_item_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">{arrear_period_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{arrear_amount_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{late_fee_1}</td></tr>\r\n<tr style=\"background:#fff5f5;\"><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">2</td><td style=\"padding:7px 8px;border:1px solid #ddd;\">{arrear_item_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">{arrear_period_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{arrear_amount_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{late_fee_2}</td></tr></tbody>\r\n<tfoot><tr style=\"background:#c62828;color:#fff;font-weight:bold;\">\r\n<td style=\"padding:9px 8px;text-align:center;\" colspan=\"3\">合计</td>\r\n<td style=\"padding:9px 8px;text-align:right;font-size:16px;\">¥{total_arrears}</td>\r\n<td style=\"padding:9px 8px;text-align:right;\">¥{total_late_fee}</td></tr></tfoot></table>\r\n<div style=\"background:#fff3e0;border:1px solid #ffcc02;border-radius:6px;padding:14px;margin-bottom:14px;\">\r\n<div style=\"font-size:14px;font-weight:bold;color:#e65100;margin-bottom:10px;\">重要提示</div>\r\n<div style=\"font-size:12px;line-height:2.2;color:#555;\">\r\n1. 请您在收到本通知后 <strong style=\"color:#c62828;\">7日内</strong> 到 翠苑新城 物业服务中心结清上述款项。<br>\r\n2. 逾期未缴,滞纳金将按日累计,并可能采取进一步催缴措施。<br>\r\n3. 如已缴纳,请忽略本通知。如有疑问请致电物业服务中心。</div></div>\r\n<div style=\"font-size:12px;color:#555;line-height:2;\">\r\n<strong>缴费地址:</strong>{company_address}<br><strong>联系电话:</strong>{service_phone}<br><strong>收款账户:</strong>{bank_name} {bank_account}</div>\r\n<div style=\"text-align:right;margin-top:20px;font-size:13px;padding-top:15px;border-top:1px solid #eee;\">\r\n<div style=\"margin-bottom:4px;\">翠苑新城 物业管理处</div><div>{urge_date}</div></div></div></div></body></html>','A4','portrait',