></table></div>\r\n<div style=\"background:#e8eaf6;padding:12px 14px;border-radius:4px;margin-bottom:12px;\">\r\n<div style=\"font-size:14px;font-weight:bold;color:#283593;margin-bottom:8px;\">家庭成员</div>\r\n<table style=\"width:100%;font-size:13px;border-collapse:collapse;\">\r\n<thead><tr style=\"border-bottom:1px solid #c5cae9;\">\r\n<th style=\"padding:5px 8px;text-align:left;\">姓名</th><th style=\"padding:5px 8px;text-align:center;\">关系</th><th style=\"padding:5px 8px;text-align:center;\">电话</th><th style=\"padding:5px 8px;text-align:left;\">备注</th></tr></thead><tbody>\r\n<tr><td style=\"padding:4px 8px;\">{member1_name}</td><td style=\"padding:4px 8px;text-align:center;\">{member1_relation}</td><td style=\"padding:4px 8px;text-align:center;\">{member1_phone}</td><td style=\"padding:4px 8px;\">{member1_remark}</td></tr>\r\n<tr style=\"background:#fafafa;\"><td style=\"padding:4px 8px;\">{member2_name}</td><td style=\"padding:4px 8px;text-align:center;\">{member2_relation}</td><td style=\"padding:4px 8px;text-align:center;\">{member2_phone}</td><td style=\"padding:4px 8px;\">{member2_remark}</td></tr>\r\n<tr><td style=\"padding:4px 8px;\">{member3_name}</td><td style=\"padding:4px 8px;text-align:center;\">{member3_relation}</td><td style=\"padding:4px 8px;text-align:center;\">{member3_phone}</td><td style=\"padding:4px 8px;\">{member3_remark}</td></tr></tbody></table></div>\r\n<div style=\"background:#fff8e1;padding:12px 14px;border-radius:4px;margin-bottom:12px;\">\r\n<div style=\"font-size:14px;font-weight:bold;color:#f57f17;margin-bottom:8px;\">车辆信息</div>\r\n<table style=\"width:100%;font-size:13px;border-collapse:collapse;\">\r\n<thead><tr style=\"border-bottom:1px solid #ffe082;\">\r\n<th style=\"padding:5px 8px;text-align:left;\">车牌号</th><th style=\"padding:5px 8px;text-align:left;\">品牌型号</th><th style=\"padding:5px 8px;text-align:left;\">颜色</th><th style=\"padding:5px 8px;text-align:left;\">车位编号</th></tr></thead><tbody>\r\n<tr><td style=\"padding:4px 8px;\"