ze:13px;margin-bottom:16px;\">\r\n<thead><tr style=\"background:#ffebee;\">\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:center;\">序号</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:left;\">费用项目</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:center;\">欠费期间</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:right;\">欠费金额(元)</th>\r\n<th style=\"padding:8px 8px;border:1px solid #ddd;text-align:right;\">滞纳金(元)</th></tr></thead><tbody>\r\n<tr><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">1</td><td style=\"padding:7px 8px;border:1px solid #ddd;\">{arrear_item_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">{arrear_period_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{arrear_amount_1}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{late_fee_1}</td></tr>\r\n<tr style=\"background:#fff5f5;\"><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">2</td><td style=\"padding:7px 8px;border:1px solid #ddd;\">{arrear_item_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:center;\">{arrear_period_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{arrear_amount_2}</td><td style=\"padding:7px 8px;border:1px solid #ddd;text-align:right;\">{late_fee_2}</td></tr></tbody>\r\n<tfoot><tr style=\"background:#c62828;color:#fff;font-weight:bold;\">\r\n<td style=\"padding:9px 8px;text-align:center;\" colspan=\"3\">合计</td>\r\n<td style=\"padding:9px 8px;text-align:right;font-size:16px;\">¥{total_arrears}</td>\r\n<td style=\"padding:9px 8px;text-align:right;\">¥{total_late_fee}</td></tr></tfoot></table>\r\n<div style=\"background:#fff3e0;border:1px solid #ffcc02;border-radius:6px;padding:14px;margin-bottom:14px;\">\r\n<div style=\"font-size:14px;font-weight:bold;color:#e65100;margin-bottom:10px;\">重要提示</div>\r\n<div style=\"font-size:12px;line-height:2.2;color:#555;\">\r\n1. 请您在收到本通知后 <strong style=\"color:#c62828;\">7日内</strong> 到 杭州喵喵至家网络有限公司 物业服务中心结清上述款项。<br>\r\n2. 逾期未缴,滞纳金将按日累计,并可能采取进一步催缴措施。<br>\r\n3. 如已缴纳,请忽略本通知。如有疑问请致电物业服务中心。</div></div>\r\n<div style=\"font-size:12px;color:#555;line-height:2;\">\r\n<strong>缴费地址:</strong>{company_address}<br><strong>联系电话:</strong>{service_phone}<br><strong>收款账户:</strong>{bank_name} {bank_account}</div>\r\n<div style=\"text-align:right;margin-top:20px;font-size:13px;padding-top:15px;border-top:1px solid #eee;\">\r\n<div style=\"margin-bottom:4px;\">杭州喵喵至家网络有限公司 物业管理处</div><div>{urge_date}</div></div></div></div></body></html>','A4','portrait',10,10,15,15,0,1,12,'2026-06-04 07:16:59','2026-06-04 07:16:59',NULL),(47,'杭州喵喵至家网络有限公司-出入放行条','form_MMZJ_gatepass','form','<!DOCTYPE html><html><head><meta charset=\"utf-8\"><style>body{font-family:\'Microsoft YaHei\',sans-serif;margin:0;padding:0}</style></head><body>\r\n<div style=\"max-width:400px;margin:0 auto;border:3px solid #2e7d32;border-radius:4px;overflow:hidden;background:#f1f8e9;\">\r\n<div style=\"background:#2e7d32;color:#fff;text-align:center;padding:12px 0;\">\r\n<div style=\"font-size:18px;font-weight:bold;letter-spacing:3px;\">杭州喵喵至家网络有限公司</div>\r\n<div style=\"font-size:12px;letter-spacing:2px;margin-top:2px;\">车辆/人员 出入放行条</div></div>\r\n<div style=\"padding:12px 15px;\">\r\n<table style=\"width:100%;font-size:13px;border-collapse:collapse;\">\r\n<tr><td style=\"padding:4px 0;color:#555;width:22%;\">编号</td><td style=\"padding:4px 0;font-weight:bold;\">{pass_no}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">放行类型</td><td style=\"padding:4px 0;font-weight:bold;\">{pass_type}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">业主姓名</td><td style=\"padding:4px 0;\">{owner_name}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">房号</td><td style=\"padding:4px 0;\">{room_number}</td></tr>\r\n<tr><td style=\"padding:4px 0;color:#555;\">联系电话</td><td style=\"padding:4px 0;\">{owner_phone}</td></tr>\r