--
-- Table structure for table `ds_repair_order`
--

DROP TABLE IF EXISTS `ds_repair_order`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_repair_order` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `order_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '工单编号',
  `title` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '报修标题',
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `owner_id` int unsigned NOT NULL DEFAULT '0' COMMENT '业主ID',
  `room_id` int unsigned NOT NULL DEFAULT '0' COMMENT '房间ID',
  `reporter` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '报修人',
  `reporter_phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '联系电话',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类型 1水 2电 3气 4门窗 5管道 6家电 7网络 8其他',
  `level` tinyint(1) NOT NULL DEFAULT '2' COMMENT '紧急程度 1普通 2紧急 3特急',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '报修内容',
  `images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '报修图片（JSON数组）',
  `source` tinyint(1) NOT NULL DEFAULT '1' COMMENT '来源 1业主端 2物业端 3电话 4现场',
  `assignee_id` int unsigned NOT NULL DEFAULT '0' COMMENT '维修人员ID',
  `assign_time` datetime DEFAULT NULL COMMENT '派单时间',
  `accept_time` datetime DEFAULT NULL COMMENT '接单时间',
  `finish_time` datetime DEFAULT NULL COMMENT '完成时间',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1待派单 2待接单 3处理中 4待验收 5已完成 6已关闭',
  `handle_content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '处理内容',
  `handle_images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci COMMENT '处理图片',
  `fee` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '维修费用',
  `fee_desc` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '费用说明',
  `rating` tinyint(1) NOT NULL DEFAULT '0' COMMENT '评分 1-5',
  `comment` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '评价',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_order_no` (`order_no`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_owner_id` (`owner_id`) USING BTREE,
  KEY `idx_assignee_id` (`assignee_id`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE,
  KEY `idx_type` (`type`) USING BTREE,
  KEY `idx_create_time` (`create_time`) USING BTREE,
  KEY `idx_delete_time` (`delete_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=46 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='报修工单';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `ds_repair_order`
--

