DROP TABLE IF EXISTS `ds_repair_worker`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_repair_worker` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `staff_id` int unsigned DEFAULT '0',
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '姓名',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '手机号',
  `openid` varchar(64) COLLATE utf8mb4_unicode_ci DEFAULT '',
  `type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '技能类型（水电、门窗等，逗号分隔）',
  `avatar` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '头像',
  `work_status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '工作状态 1空闲 2繁忙 3休息',
  `order_count` int NOT NULL DEFAULT '0' COMMENT '接单总数',
  `finish_count` int NOT NULL DEFAULT '0' COMMENT '完成总数',
  `avg_rating` decimal(3,2) NOT NULL DEFAULT '0.00' COMMENT '平均评分',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1在职 0离职',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE,
  KEY `idx_delete_time` (`delete_time`) USING BTREE,
  KEY `idx_staff_id` (`staff_id`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=12 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='维修人员';
/*!40101 SET character_set_client = @saved_cs_client */;

