--
-- Table structure for table `ds_room`
--

DROP TABLE IF EXISTS `ds_room`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `ds_room` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `community_id` int unsigned NOT NULL DEFAULT '0' COMMENT '小区ID',
  `building_id` int unsigned NOT NULL DEFAULT '0' COMMENT '楼栋ID',
  `building_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '楼栋名称',
  `unit` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '单元',
  `floor` int NOT NULL DEFAULT '0' COMMENT '楼层',
  `room_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '房间编号（如101、A101）',
  `type` tinyint(1) NOT NULL DEFAULT '1' COMMENT '类型 1住宅 2商铺 3写字楼 4车位 5仓库',
  `area` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '建筑面积(㎡)',
  `usable_area` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '套内面积(㎡)',
  `orientation` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '朝向 东/南/西/北/南北',
  `layout` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '户型（如三室两厅）',
  `decorate_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '装修状态 0毛坯 1简装 2精装 3豪装',
  `status` tinyint(1) NOT NULL DEFAULT '1' COMMENT '状态 1未售 2已售 3已租 4自用 5空置',
  `owner_id` int unsigned NOT NULL DEFAULT '0' COMMENT '业主ID',
  `is_living` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否入住 0否 1是',
  `check_in_date` date DEFAULT NULL COMMENT '入住日期',
  `property_fee_rate` decimal(10,4) NOT NULL DEFAULT '0.0000' COMMENT '物业费单价(元/㎡/月)',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT '' COMMENT '备注',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime DEFAULT NULL COMMENT '删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE KEY `uk_building_room` (`building_id`,`room_number`) USING BTREE,
  KEY `idx_community_id` (`community_id`) USING BTREE,
  KEY `idx_building_id` (`building_id`) USING BTREE,
  KEY `idx_owner_id` (`owner_id`) USING BTREE,
  KEY `idx_status` (`status`) USING BTREE,
  KEY `idx_room_number` (`room_number`) USING BTREE,
  KEY `idx_delete_time` (`delete_time`) USING BTREE
) ENGINE=InnoDB AUTO_INCREMENT=7395 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci ROW_FORMAT=DYNAMIC COMMENT='房间';
/*!40101 SET character_set_client = @saved_cs_client */;

