  `overtime_pay` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '加班费',
  `subsidy` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '补贴',
  `deduction` decimal(10,2) NOT NULL DEFAULT '0.00' COMMENT '扣款',
