INSERT INTO `ds_supplier_evaluation` VALUES (1,1,5,'物业管理员','蓝天保洁服务非常专业，清洁质量高，员工态度好，业主反馈满意度高。','2026-06-02 20:13:50',NULL),(2,1,4,'业主代表','整体不错，偶尔有些角落清理不够细致。','2026-06-02 20:13:50',NULL),(3,2,4,'工程部主管','恒通工程响应及时，维修质量可以，价格合理。','2026-06-02 20:13:50',NULL),(4,2,5,'物业管理员','最近一次水管抢修非常迅速，很满意。','2026-06-02 20:13:50',NULL),(5,3,5,'环境主管','绿源绿化效果很好，花草养护到位，小区环境明显提升。','2026-06-02 20:13:50',NULL),(6,4,4,'安保队长','安盾的保安人员纪律性强，但换岗交接偶尔有延迟。','2026-06-02 20:13:50',NULL),(7,4,3,'业主委员会','夜班巡逻力度还需加强。','2026-06-02 20:13:50',NULL),(8,5,5,'采购部','星辰物资供应及时，产品齐全，价格合理。','2026-06-02 20:13:50',NULL);
